 /*******
 *   Attribute Rule Library                                                          *
 *                                                                                   *
 *   This is a collection of utility methods that can be called from other Rules     *
 *   and Workflows to work with Identity and Account Attribute values.               *
 *                                                                                   *
 *   To include a library in another Rule, use this format:                          *
 *     <Rule ......>                                                                 *
 *       <ReferencedRules>                                                           *
 *         <Reference class="sailpoint.object.Rule" name="Attribute Rule Library"/>  *
 *       </ReferencedRules>                                                          *
 *       ..                                                                          *
 *       ..                                                                          *
 *     </Rule>                                                                       *
 *                                                                                   *
 *   To include a library in a Workflow, use this format:                            *
 *                                                                                   *
 *     <Workflow ......>                                                             *
 *       <RuleLibraries>                                                             *
 *         <Reference class="sailpoint.object.Rule" name="Attribute Rule Library" /> *
 *       </RuleLibraries>                                                            *
 *       ..                                                                          *
 *       ..                                                                          *
 *     </Workflow>                                                                   *
 ******/

