 String msgSeparator = "*********************************************";

 /*****
   Method to validate the phone number
  *****/
 public boolean validatePhoneNumber(String phoneNumber){
   if ( plog.isTraceEnabled() ){
     plog.trace( "ARL-SE-004::Entering Attribute Rule Library - validatePhoneNumber ");
   }
   Pattern regexValidPhoneNum = Pattern.compile("^\\s*(?:\\+?(\\d{1,3}))?[-. (]*(\\d{2,4})[-. )]*(\\d{2,4})[-. ]*(\\d{2,4})(?: *x(\\d+))?\\s*$", Pattern.CASE_INSENSITIVE);
   Matcher phonematcher = regexValidPhoneNum.matcher(phoneNumber);
   return phonematcher.find();
 }

 /*****
   Method to validate the email string
  *****/
 public boolean validateEmail(String emailStr){
   if ( plog.isTraceEnabled() ){
     plog.trace( "ARL-SE-003::Entering Attribute Rule Library - validateEmail ");
   }
   Pattern regexValidEmail = Pattern.compile("^[A-Za-z_0-9\\.'-]{1,64}@[A-Za-z_0-9\\.'-]+\\.[A-Za-z_\\.]{2,7}$", Pattern.CASE_INSENSITIVE);
   Matcher mailMatcher = regexValidEmail.matcher(emailStr);
   return mailMatcher.find();
 }

 /*****
   Method to sendemail notification based on the arguments provided
  *****/
 public sendEmailNotification(String emailTemplateName, Map argMaps,String toAdress){
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-SE-001::Entering Attribute Rule Library - sendEmailNotification "  );
   }
   if(null != emailTemplateName && null != toAdress){
     EmailTemplate emailTemplate = context.getObjectByName(EmailTemplate.class,emailTemplateName);
     if(null != emailTemplate){
       EmailOptions emailOptions = new EmailOptions(toAdress,argMaps);
       context.sendEmailNotification(emailTemplate, emailOptions);
     }
   }
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-SE-002 ::Exiting- sendEmailNotification "  );
   }
 }

 /*******
   Get Workday TMNA Org Attribute. This is for multiple account. to be picked from the before operation rule from jobnavi sup org
 *******/
 public static Object getWorkDayTMNAOrgAttribute( SailPointContext context, Identity identity, String applicationName, String attributeName, String nativeId ) {
   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-GWTOA-001 Entering Attribute Rule Library - Get Application Attribute: " + attributeName );
   }
   IdentityService identityService = new IdentityService(context);

   Object attributeValue;
   try {
     if(Util.isNotNullOrEmpty(nativeId)){
       List links =  identityService.getLinks( identity, context.getObjectByName( Application.class, applicationName ) );

       if ( links != null && !links.isEmpty() ) {
         Attributes wdAtts = new Attributes();

         for ( Link account : links ) {
           String orgId = account.getAttribute("OrganizationalReferenceID");
           if(nativeId.equalsIgnoreCase(orgId)){
             if(null != account.getAttribute(attributeName)){
               attributeValue = account.getAttribute(attributeName);
             }
           }
         }

         if( plog.isTraceEnabled() ) {
           if ( attributeValue != null ) {
             plog.trace( "ARL-GWTOA-002 Attribute " + attributeName + ": " + attributeValue.toString() );
           }
         }
       }
     }
   } catch ( Exception e ) {
     plog.error( "ARL-GWTOA-003 Error Fetching Attribute" + e.toString() );
     return null;
   }

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GWTOA-004 Exiting Attribute Rule Library - Get Application Attribute" );
     plog.trace( msgSeparator );
   }

   if ( attributeValue != null ) {
     if ( attributeValue instanceof String ) {
       attributeValue = attributeValue.toString().trim();
     }
     else if ( attributeValue instanceof List ) {
       attributeValue = new ArrayList(attributeValue);
     }
   }
   return attributeValue;
 }
 /*******
   Get Identity Status as Y (active) or N (inactive)
 *******/
 public static Object getIdentityStatusYN(SailPointContext context, Identity identity){
   String isActive = "";
   Boolean inactive = identity.isInactive();
   if(inactive == true){
     isActive="N";
   }else{
     isActive="Y";
   }
   return isActive;
 }

 /*******
   Get Identity Attribute
 *******/
 public static Object getIdentityAttribute( SailPointContext context, Identity identity, String attributeName ) {
   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-GIA-001 Entering Attribute Rule Library - Get Identity Attribute: " + attributeName );
   }

   Object attributeValue;
   try {
     attributeValue = identity.getAttribute( attributeName );
     if( plog.isTraceEnabled() ) {
       if ( attributeValue != null ) {
         plog.trace( "ARL-GIA-002 Attribute " + attributeName + ": " + attributeValue.toString() );
       } else {
         plog.trace( "ARL-GIA-003 Attribute " + attributeName + ": is NULL" );
       }
     }
   } catch ( Exception e ) {
     plog.error( "ARL-GIA-004 Error Fetching Attribute" + e.toString() );
     return null;
   }

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GIA-005 Exiting Attribute Rule Library - Get Identity Attribute" );
     plog.trace( msgSeparator );
   }

   if ( attributeValue != null ) {
     if ( attributeValue instanceof String ) {
       attributeValue = attributeValue.toString().trim();
     }
     else if ( attributeValue instanceof List ) {
       attributeValue = new ArrayList(attributeValue);
     }
   }

   return attributeValue;
 }

 /*******
   Get Identity Display Name
 *******/
 public static String getIdentityDisplayName(Identity identity) {
   String displayName = getIdentityAttribute(context, identity, "displayName") != null ? getIdentityAttribute(context, identity, "displayName") : "";
   displayName = (String) displayName.split(" \\(")[0];
   return displayName;
 }

  /*******
 Generate First Name for SAP
 ********/
 public String getIdentitySAPFirstname(Identity identity) {
   String firstName = getIdentityAttribute(context, identity, "firstname") != null ? getIdentityAttribute(context, identity, "firstname") : "";
   String middleName = getIdentityAttribute(context, identity, "middleName") != null ? getIdentityAttribute(context, identity, "middleName") : "";
   String sapFirstName;
   if (!middleName.isEmpty()) {
     sapFirstName = firstName + " " + middleName;
   }
   else {
     sapFirstName = firstName;
   }
   return sapFirstName;
 }
 /*******
   Get String Attribute Value
 *******/
 public static String getLinkAttribtueStringValue( Link appLink, String attributeName ) {
   String newValue = null;
   if(Util.isNotNullOrEmpty(appLink.getAttribute(attributeName))){
     newValue = appLink.getAttribute(attributeName);
   }
   if(plog.isTraceEnabled()){
     plog.trace("ARL-GSAV-001 :: method getLinkAttribtueStringValue in Attribute Rule Library is returning value == "+newValue);
   }
   return newValue;  
 }
 /*******
   Get Application Attribute
 *******/
 public static Object getApplicationAttribute( SailPointContext context, Identity identity, String applicationName, String attributeName ) {
   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-GAA-001 Entering Attribute Rule Library - Get Application Attribute: " + attributeName );
   }
   IdentityService identityService = new IdentityService(context);

   Object attributeValue;
   try {

     List links =  identityService.getLinks( identity, context.getObjectByName( Application.class, applicationName ) );

     if ( links != null && !links.isEmpty() ) {
       Attributes wdAtts = new Attributes();

       for ( Link account : links ) {
         wdAtts = account.getAttributes();
       }
       if(null != wdAtts.get( attributeName )) {
         attributeValue = wdAtts.get( attributeName );
       }
       if( plog.isTraceEnabled() ) {
         if ( attributeValue != null ) {
           plog.trace( "ARL-GAA-002 Attribute " + attributeName + ": " + attributeValue.toString() );
         }
       }
     }
   } catch ( Exception e ) {
     plog.error( "ARL-GAA-003 Error Fetching Attribute" + e.toString() );
     return null;
   }

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GAA-004 Exiting Attribute Rule Library - Get Application Attribute" );
     plog.trace( msgSeparator );
   }

   if ( attributeValue != null ) {
     if ( attributeValue instanceof String ) {
       attributeValue = attributeValue.toString().trim();
     }
     else if ( attributeValue instanceof List ) {
       attributeValue = new ArrayList(attributeValue);
     }
   }

   return attributeValue;

 }

/*******
   Get UpperCase attribute value
 *******/  
 public static String getUpperCaseAttributeValue(String attributeValue){
   if(Util.isNotNullOrEmpty(attributeValue)){
       attributeValue= attributeValue.toUpperCase();
     }
   return attributeValue;  
 }

/*******
   Get Capital Case attribute value
 *******/  
 public static String getCapitalCaseAttributeValue(String attributeValue){
   if(Util.isNotNullOrEmpty(attributeValue)){
     final String delimeters = " '-.’("; // the character following this special char to be capitalized   
     StringBuilder sb = new StringBuilder();
     boolean capNext = true;
     for (char c : attributeValue.toCharArray()) {
       c = (capNext) ? Character.toUpperCase(c) : Character.toLowerCase(c);
       sb.append(c);
       capNext = (delimeters.indexOf((int) c) >= 0); // explicit cast not needed
     }
     return sb.toString();
   }
   return attributeValue;  
 }

 /*******
   Get Attribute from Identity then Application
 *******/
 public static Object getAttribute( SailPointContext context, Identity identity, String applicationName, String attributeName ) {
   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-GA-001 Entering Attribute Rule Library - Get Attribute" );
   }

   Object attributeValue = null;
   try {

     attributeValue = getIdentityAttribute( context, identity, attributeName );

     if ( ( attributeValue == null ) || ( (String)attributeValue.length() == 0 ) ) {
       attributeValue = getApplicationAttribute( context, identity, applicationName, attributeName );
     }

     if( plog.isTraceEnabled() ) {
       if ( attributeValue != null ) {
         plog.trace( "ARL-GA-002 Attribute " + attributeName + ": " + attributeValue.toString() );
       }
     }

   } catch ( Exception e ) {
     plog.error( "ARL-GA-003 Error Fetching Attribute" + e.toString() );
     return null;
   }

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GA-004 Exiting Attribute Rule Library - Get Attribute" );
     plog.trace( msgSeparator );
   }

   if ( attributeValue != null ) {
     if ( attributeValue instanceof String ) {
       attributeValue = attributeValue.toString().trim();
     }
     else if ( attributeValue instanceof List ) {
       attributeValue = new ArrayList(attributeValue);
     }
   }

   return attributeValue;

 }

 /*******
   Get userProncipalName or mail from Azure for Identity Attribute
 *******/
 public static String getUPNOrMail( SailPointContext context, Link link ) {
   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-GUM-001 Entering Attribute Rule Library - getUPNOrMail" );
   }

   String azureEmail = "";
   String azureUserPrincipalName = "";

   try {
     azureEmail = link.getAttribute( "mail" );
     azureEmail = azureEmail != null ? azureEmail : "";
     if ( plog.isTraceEnabled() ) {
       plog.trace( "ARL-GUM-002 Azure mail: " + azureEmail );
     }

     azureUserPrincipalName = link.getAttribute( "userPrincipalName" );
     azureUserPrincipalName = azureUserPrincipalName != null ? azureUserPrincipalName : "";
     if ( plog.isTraceEnabled() ) {
       plog.trace( "ARL-GUM-003 Azure userPrincipalName: " + azureUserPrincipalName );
     }

   } catch ( Exception ex ) {
     plog.error( "ARL-GUM-004 ERROR Fetching Azure Attributes: " + e.toString() );
     return null;
   }

   if ( azureUserPrincipalName.contains( "#EXT#" ) ) {
     azureUserPrincipalName = azureEmail;
   }

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GUM-005 Returning: " + azureUserPrincipalName + " as userPrincipalName" );
   }

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GUM-006 Exiting Attribute Rule Library - getUPNOrMail" );
     plog.trace( msgSeparator );
   }

   return azureUserPrincipalName;
 }

 /*******
   Select the primary UPN from Azure AD accounts
 *******/
 public static String getUPNOrMailSelect( SailPointContext context, Link link, Identity identity )
 {
   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-GUMS-001 Entering Attribute Rule Library - getUPNOrMailSelect" );
   }

   Boolean primayAccount = false;
   Boolean otherMemberPresent = false;
   Boolean otherPrimaryAccountPresent = false;
   IdentityService idService=new IdentityService(context);
   Application azureApp=context.getObjectByName(Application.class,"Azure AD");
   List azureLinks=idService.getLinks(identity,azureApp);
   String upn = null;

   if (azureLinks != null) {
     int linkCount = azureLinks.size();
     String userType = link.getAttribute( "userType" );
     List assignedLicenses = link.getAttribute("assignedLicenses");
     String linkObjectID = link.getNativeIdentity();

     if ( plog.isTraceEnabled() ) {
       plog.trace("ARL-GUMS-002 getUPNOrMailSelect : identityName : "+ identity.getName());
       plog.trace("ARL-GUMS-003 getUPNOrMailSelect : Native Identity : "+ linkObjectID);
     }

     if (linkCount == 1) {
       primayAccount = true;
     }
     else if (linkCount > 1) // User with more than one Azure account
     {
       if (assignedLicenses != null && assignedLicenses.contains("ENTERPRISEPREMIUM") && userType != null && userType.equalsIgnoreCase( "Member" ))
       {
         // In case there are more than one account with userType Member and a valid mail attribute
         // both accounts would return UPN for update. This usually implies bad data
         primayAccount = true;
       }
       else
       {
         for (Link azureLink : azureLinks) // Scan link for other member accounts
         {
           String userTypeAzure = azureLink.getAttribute( "userType" );
           List assignedAzureLicenses = azureLink.getAttribute("assignedLicenses");
           String azureLinkObjectID = azureLink.getNativeIdentity();

           if (assignedAzureLicenses != null && assignedAzureLicenses.contains("ENTERPRISEPREMIUM") && userTypeAzure !=null && userTypeAzure.equalsIgnoreCase( "Member" ) && !linkObjectID.equalsIgnoreCase( azureLinkObjectID ) )
           {
             // In case there exists atleast one other account with userType Member and a valid mail attribute.
             // currentUPN is not to be sent.
             otherPrimaryAccountPresent = true;
           }
           else if (userTypeAzure !=null && userTypeAzure.equalsIgnoreCase( "Member" ) && !linkObjectID.equalsIgnoreCase( azureLinkObjectID ))
           {
             // To be used to check for users who have member type and guest type accounts
             // UPN from Member type to be used
             otherMemberPresent = true;
           }
         }
         if (userType !=null && userType.equalsIgnoreCase( "Guest" ) && otherMemberPresent) {
           primayAccount = false;
         }
         else if (!otherPrimaryAccountPresent)
         {
           // Applicable if there exists a different account that matches the primary account critiera
           primayAccount = true;
         }
       }
     }
     if (primayAccount) {
       upn = getUPNOrMail( context, link );
       if ( plog.isTraceEnabled() ) {
         plog.trace("ARL-GUMS-004 getUPNOrMailSelect : Primary Account Identified : " + linkObjectID);
       }
     }
     if ( plog.isTraceEnabled() ) {
       String upnLog = (upn != null)? upn : "NULL";
       plog.trace("ARL-GUMS-006 getUPNOrMailSelect : UPN Selected : "+ upnLog);
     }

   }

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GUMS-007 Exiting Attribute Rule Library - getUPNOrMailSelect" );
     plog.trace( msgSeparator );
   }
   return upn;
 }
     /*******
   Get time stamp based on the zone as required format either dd-mm-yyyy or yyyy/mm/dd
 *******/
 public static String getTimeStamp(String zone, String format)
 {

   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-GTS-001 Entering Attribute Rule Library - get TimeStamp()" );
     plog.trace( "ARL-GTS-002 Zone : "+zone+" required format is "+format );
   }
   if ( zone != null && format != null ) {
     ZoneId z = ZoneId.of(zone);
     Instant instant = Instant.now();
     ZonedDateTime zdt = instant.atZone( z );
     DateTimeFormatter format = DateTimeFormatter.ofPattern(format); //yyyy-mm-dd format
     return format.format(zdt).toString();
   }
 }

 /*******
   Get requester/requestee from provisioning plan or project
 *******/
 public static String getAccessRequstAttributes(ProvisioningProject project, String requestValue) {
   if ( plog.isTraceEnabled() ) {
   plog.trace( msgSeparator );
   plog.trace( "ARL-GARA-001 Entering Attribute Rule Library - getAccessRequstAttributes" );
   plog.trace( "ARL-GARA-002 request attributeValue : "+requestValue);
   }
   if( project != null ) {
     if( requestValue != null && requestValue.equalsIgnoreCase("requester") )
       return project.getRequester();

       if( requestValue != null && requestValue.equalsIgnoreCase("requestee") )
         return project.getIdentity();
   }
 }

 /*******
   Generate GUID
 *******/
 public static String generateGUID() {
   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-GGUID-001 Entering Attribute Rule Library - generateGUID" );
   }

   String randomHexGUID = UUID.randomUUID().toString().replaceAll("-", "").toUpperCase();

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GGUID-002 Generated GUID: " + randomHexGUID );
     plog.trace( "ARL-GGUID-003 Exiting Attribute Rule Library - generateGUID" );
     plog.trace( msgSeparator );
   }

   return randomHexGUID;
 }

 /*******
   Get User Types
 *******/
 public static Object getUserTypes( SailPointContext context ) {
   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-GUT-001 Entering Attribute Rule Library - getUserTypes" );
   }

   List userTypes = new ArrayList();
   List userTypeObjects = new ArrayList();

   ObjectConfig identityConfig = context.getObjectByName( ObjectConfig.class, "Identity" );

   userTypeObjects = identityConfig.getIdentityTypesList();

   if ( userTypeObjects != null && !userTypeObjects.isEmpty() ) {
     for ( IdentityTypeDefinition identityTypeDef : userTypeObjects ) {
       if ( plog.isTraceEnabled() ) {
         plog.trace( "ARL-GUT-002 Identity Type: \n" + identityTypeDef.toXml() );
       }
       String userType = identityTypeDef.getName();
       userTypes.add( userType );
     }
   }

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GUT-003 Identity Types" + userTypes.toString() );
     plog.trace( "ARL-GUT-004 Exiting Attribute Rule Library - getUserTypes" );
     plog.trace( msgSeparator );
   }

   return userTypes;
 }

 /*******
   Get fetch Time from the String
 *******/
 public static String getTime( String shiftDateTime ) {
   String strTime = "";
   String dateTimeFormatted = "";
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GT-001 Entering Attribute Rule Library - getTime" );
   }
   try {
     if(shiftDateTime!=null)
     {
       List<String> resultList = Splitter.on(' ').trimResults().omitEmptyStrings().splitToList(shiftDateTime);
       for(String splittedString : resultList) {
         if(splittedString.contains(":")) {
           strTime = splittedString;
           break;
         }
       }
       DateFormat inDateFormat = new SimpleDateFormat( "H:m:s");
       Date dateTime = inDateFormat.parse(strTime);
       DateFormat outDateFormat = new SimpleDateFormat( "HH:mm:ss");
       dateTimeFormatted = outDateFormat.format(dateTime);
       if ( plog.isTraceEnabled() ) {
         plog.trace( "ARL-GT-002 dateTimeFormatted: " + dateTimeFormatted );
       }
     }
   }
   catch ( Exception ex ) {
     plog.error( "ARL-GT-003 ERROR Fetching SupplierPlant ShiftTime Attributes: " + ex.toString() );
     return null;
   }
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GT-004 Exiting Attribute Rule Library - getTime" );
     plog.trace( msgSeparator );
   }
   return dateTimeFormatted;
 }

 /*******
   Generate New mailNicknames
   This will generate a Hash of new email nicknames for a user in order priority for use
 *******/
 public static Object generateMailNicknames( SailPointContext context, String firstname, String lastname, String middlename, Integer startNumber ) {
   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-GMNN-001 Entering Attribute Rule Library - generateMailNicknames" );
   }
   Map mailNicknameHash = new TreeMap();
   String mailNickname = "";
   int maxLength = 64;

   String middleInitial = "";

   firstname = firstname != null ? firstname : "";
   lastname = lastname != null ? lastname : "";
   middlename = middlename != null ? middlename : "";

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GMNN-002 First Name : " + firstname );
     plog.trace( "ARL-GMNN-003 Last Name  : " + lastname );
     plog.trace( "ARL-GMNN-004 Middle Name: " + middlename );
   }

   if ( firstname.length() > 0 && lastname.length() > 0 ) {
     mailNickname = firstname + "." + lastname;
     mailNickname = scrubMailNickname( mailNickname, maxLength );
     mailNicknameHash.put( 1, mailNickname );
   }

   if ( startNumber <= 0 ) {
     // Generate non numeric mail nicknames
     if ( firstname.length() > 0 && lastname.length() > 0 ) {

       if ( middlename.length() > 0 ) {
         middleInitial = middlename.substring(0, 1);
         mailNickname = firstname + "." + middlename + "." + lastname;
         mailNickname = scrubMailNickname( mailNickname, maxLength );
         mailNicknameHash.put( 2, mailNickname );

         mailNickname = firstname + "." + middleInitial + "." + lastname;
         mailNickname = scrubMailNickname( mailNickname, maxLength );
         mailNicknameHash.put( 3, mailNickname );
       }
     }
   } else {
     // Generate numeric mail nicknames 5 at a time
       String numericBase = mailNicknameHash.get( 1 );
     for ( int i = startNumber + 3; i < startNumber + 8; i++ ) {
       mailNickname = numericBase + ( i - 3 );
       mailNickname = scrubMailNickname( mailNickname, maxLength - 1 );
       mailNicknameHash.put( i, mailNickname );
     }
   }

   if ( plog.isTraceEnabled() ) {
     for ( Map.Entry entry : mailNicknameHash.entrySet() ) {
         plog.trace( "[" + entry.getKey() + ", " + entry.getValue() + "]\n" );
     }
     plog.trace( "ARL-GMNN-005 Exiting Attribute Rule Library - generateMailNicknames" );
     plog.trace( msgSeparator );
   }
   return mailNicknameHash;
 }

 /*******
   Generate AD user DN
   This will generate a DN for a new AD user account
   TODO: Update logic to select
     1) Forest
     2) Container
     3) cn attribute
 *******/
 public static String generateADDN( SailPointContext context, Identity identity, Application application ) {
   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-GADDN-001 Entering Attribute Rule Library - generateADDN" );
   }

   Map forestContainers = application.getAttributeValue( "userContainers" );

   String userDN = "";
   String targetDomain = "";
   String userContainer = "users";
   String accountAttribute = "workday_id";


   if ( forestContainers != null && !forestContainers.isEmpty() ) {

     if ( plog.isTraceEnabled() ) {
       plog.trace( "ARL-GADDN-001 forestContainers:\n" + forestContainers.toString() );
     }

     Set forestContainerKeySet = forestContainers.keySet();
     for ( String key : forestContainerKeySet ) {
       targetDomain = key;
     }

     Map domainContainers = forestContainers.get( targetDomain );
     String baseDN = domainContainers.get( userContainer );

     String workdayID = identity.getAttribute( accountAttribute );

     userDN = "cn=" + workdayID + "," + baseDN;
     if ( plog.isTraceEnabled() ) {
       plog.trace( "ARL-GADDN-002 User distingushedName: " + userDN );
     }
   }

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GADDN-003 Exiting Attribute Rule Library - generateADDN" );
     plog.trace( msgSeparator );

   }
   return userDN;
 }
 /*
   Generate AD ENGuser DN
   This will generate a DN for a new AD user account
   Based on the Group requested OU will be provisioned for user  
 */
 public static String generateADEngDN( SailPointContext context, Identity identity, Application application, Object groupName ) {
   if ( plog.isTraceEnabled() ) {
     plog.trace("ADENGDN-001:: Entering Attribute Rule Library generateADEngDN" );
   }
   Map OUContainers = application.getAttributeValue("OUNames");
   String userDN = "";
   String accountAttribute = "workday_id";
   String baseDN="";
   if (!(Util.isEmpty(OUContainers))) {
     if ( plog.isTraceEnabled() ) {
       plog.trace( "ADENGDN-002::OUContainers:\n" + OUContainers.toString() );
     }
     for ( Map.Entry OUDomainEntry : OUContainers.entrySet() )  {
       String groupDN = OUDomainEntry.getKey();
       String OUDomain = OUDomainEntry.getValue();
       String reqGroup = groupName.toString();
       if ( groupDN.equalsIgnoreCase( reqGroup ) ) {
         baseDN = OUDomain;
       }
     }
   }
   String workdayID = identity.getAttribute( accountAttribute );
   userDN = "cn=" + workdayID + "," + baseDN;
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ADENGDN-003::User distingushedName: " + userDN );
   }
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ADENGDN-004::Exiting Attribute Rule Library - generateADDN" );
   }
   return userDN;
 }
 /*******
   Get Manager AD user DN
 *******/
 public static String getManagerADDN( SailPointContext context, Identity identity, Application application ) {
   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-GMADDN-001 Entering Attribute Rule Library - getManagerADDN" );
   }

   Identity manager = identity.getManager();

   IdentityService identityService = new IdentityService( context );
   String result = "";

   if ( manager != null ) {

     String managerID = manager.getName();

     List links =  identityService.getLinks( manager, application );

     if ( links != null && !links.isEmpty() ) {
       Attributes wdAtts = new Attributes();

       if ( links.size() == 1 ) {
         Link account = links.get( 0 );
         wdAtts = account.getAttributes();
         result = wdAtts.get( "distinguishedName" );
       } else {
         for ( Link account : links ) {
           wdAtts = account.getAttributes();
           String sAMAccountName = wdAtts.get( "sAMAccountName" );

           if ( managerID.equalsIgnoreCase( sAMAccountName ) ) {
             result = wdAtts.get( "distinguishedName" );
           }
         }
       }
     }
   }

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GMADDN-002 Exiting Attribute Rule Library - getManagerADDN" );
     plog.trace( msgSeparator );
   }

   return result;
 }

 /*******
   Get Manager Azure userPrincipalName to populate for Azure MTM and Azure TMNA PIM applications
 *******/
 public static String getManagerAzureUpn( SailPointContext context, Identity identity, Application application ) {

   plog.trace( "ARL-GMADDN-090 Entering Attribute Rule Library - getManagerAzureObjId" );
   Identity manager = identity.getManager();
   IdentityService identityService = new IdentityService( context );
   String result = "";
   /*******
     Checking user's manager Azure AD link to see if account is synchronized and member type then return userPrincipalName otherwise return blank
   *******/
   if ( manager != null ) {
     List links =  identityService.getLinks( manager, application );
     if(Util.nullSafeSize(links) > 0){
       Link account = links.get( 0 );
       if(Util.isNotNullOrEmpty(account.getAttribute("userType"))&& account.getAttribute("userType").equalsIgnoreCase("Member") && 
       account.getAttribute("onPremisesSyncEnabled") != null && account.getAttribute("onPremisesSyncEnabled") == true && Util.isNotNullOrEmpty(account.getAttribute("userPrincipalName")) ){
         result = account.getAttribute( "userPrincipalName" );
       }
     }
   }
   plog.trace( "ARL-GMADDN-091 Returned userPrincipalName" +result );
   return result;
 }

 /******
 convertNonEnglishCharacters
 Converts non english charecters like "José" to english "Jose".
 ******/
 public static String convertNonEnglishCharacters(String text) {
   String normalizedText = Normalizer.normalize(text, Normalizer.Form.NFD);
   Pattern pattern = Pattern.compile("\\p{M}");
   return pattern.matcher(normalizedText).replaceAll("");
 }

 /*******
   Scrub mailNicknames
   This will Scrub a mail nickname to meet standards
 *******/
 public static String scrubMailNickname( String mailNickname, int maxLength ) {
   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-SMNN-001 Entering Attribute Rule Library - scrubMailNickname" );
   }

   // Convert case to lower
   mailNickname = mailNickname.toLowerCase();
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-SMNN-002 mailNickname lower: " + mailNickname );
   }

   // Convert Special non english charecters like "José" to english.
   mailNickname = convertNonEnglishCharacters( mailNickname);
   plog.trace( "ARL-SMNN-002.1 mailNickname converting Non English Characters : " + mailNickname );

   // Change whitespace to "."
   mailNickname = mailNickname.replaceAll( "\\s+", "." );
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-SMNN-003 mailNickname no whitespace: " + mailNickname );
   }
   // Remove illeagal characters according to RFC-5321
   mailNickname = mailNickname.replaceAll( "[^0-9A-Za-z.!#$%&*+-\\/=?^_{|}~]", "" );
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-SMNN -004 mailNickname no illegal characters: " + mailNickname );
   }
   // Change consecutive periods to a single period
   mailNickname = mailNickname.replaceAll( "[.][.]+", "." );
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-SMNN-005 mailNickname replace double .: " + mailNickname );
   }
   // remove non ascii characters
   mailNickname = mailNickname.replaceAll("[^\\x20-\\x7e]", "");
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-SMNN-006 mailNickname remove non ascii characters: " + mailNickname );
   }
   // Remove leading period
   mailNickname = mailNickname.replaceAll( "^[.]+", "" );
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-SMNN-007 mailNickname remove leading .: " + mailNickname );
   }
   // Remove trailing period
   mailNickname = mailNickname.replaceAll( "[.]+$", "" );
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-SMNN-008 mailNickname remove trailing .: " + mailNickname );
   }
   // Remove comma 
   mailNickname = mailNickname.replaceAll( "[,]", "" );
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-SE-005::mailNickname remove comma: " + mailNickname );
   }
   // Trim to max length allowed

   maxLength = maxLength < mailNickname.length() ? maxLength : mailNickname.length();

   mailNickname = mailNickname.substring( 0, maxLength );

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-SMNN-009 Scrubbed Mail Nickname: " + mailNickname );
     plog.trace( "ARL-SMNN-010 Exiting Attribute Rule Library - scrubMailNickname" );
     plog.trace( msgSeparator );
   }
   return mailNickname;
 }

 /*******
 Search SailPoint for existance of UPN and Mail
  *******/
 public Object isSailPointMailNicknamePresent( SailPointContext context, Object mailNicknameHash ) {
   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-ISMNP-001 Entering Azure AD Rule Library - isSailPointMailNicknamePresent" );
   }

   List usedMailNicknames = new ArrayList();
   String nicknameFilters = "";

   List nickanameFilterList = new ArrayList();

   for ( Object myKey : mailNicknameHash.keySet() ) {
     nickanameFilterList.add( Filter.like( "userPrincipalName", mailNicknameHash.get( myKey ) + "@", Filter.MatchMode.START ) );
   }

   Filter mailNicknameFilter = ( Filter.or( nickanameFilterList ) );

   QueryOptions qo=new QueryOptions();

   qo.addFilter( mailNicknameFilter );

   ArrayList colsToRead = new ArrayList();
   colsToRead.add( "userPrincipalName" );
   colsToRead.add( "email" );

   Iterator it = context.search( Identity.class, qo, colsToRead );

   if ( it != null ) {
     while ( it.hasNext() ) {
       Object [] thisRecord = it.next();

       String userPrincipalName = thisRecord[0];
       String emailAddress = thisRecord[1];

       if ( userPrincipalName != null && !userPrincipalName.trim().isEmpty() ) {
         usedMailNicknames.add( userPrincipalName.split( "@" )[ 0 ] );
       }
       if ( emailAddress != null && !emailAddress.trim().isEmpty() ) {
         usedMailNicknames.add( emailAddress.split( "@" )[ 0 ] );
       }
     }
   }
   Util.flushIterator(it);
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-ISMNP-002 Exiting Attribute Rule Library - isSailPointMailNicknamePresent" );
     plog.trace( msgSeparator );
   }

   return usedMailNicknames;
 }

 /*******
   To set AZURE MFA
 *******/
 public boolean registerAzureMfaPhone( SailPointContext context, String identityName, String phone ) {
   IdentityService idService = new IdentityService(context);
   Application azureApp = context.getObjectByName(Application.class, "Azure AD");
   String upn = null;
   String nativeIdentity = null;
   String number = phone;
   Identity identity = context.getObjectByName(Identity.class, identityName);
   List azureLinks = idService.getLinks(identity, azureApp);
   if ( Util.nullSafeSize(azureLinks) > 0 ) {
     if ( azureLinks.size() == 1 ) {
       Link account = (Link) azureLinks.get(0);
       upn = account.getAttribute("userPrincipalName");
       nativeIdentity = account.getNativeIdentity();
     }
   }
   if (null != upn && !upn.contains("#EXT#")) {
     return setMfaPhoneWithMicrosoftGraph( azureApp, number, upn, nativeIdentity );
   }
   return false;
 }

 /*******
 return first available unique email address
  *******/
 public String uniqueMailNickname( SailPointContext context, Application app, String firstname, String lastname, String middlename, Identity identity ) {
   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-UMNN-001 Entering Azure AD Rule Library - uniqueMailNickname" );
   }

   TreeMap mailNicknameHash = new TreeMap();
   TreeMap interateHash = new TreeMap();

   Integer startNumber = 0;
   do {
     mailNicknameHash.putAll( generateMailNicknames( context, firstname, lastname, middlename, startNumber ) );
     if ( plog.isTraceEnabled() ) {
       plog.trace( "ARL-UMNN-002 mailNicknameHash" );
       for ( Map.Entry entry : mailNicknameHash.entrySet() ) {
         plog.trace( "ARL-UMNN-003 [" + entry.getKey() + ", " + entry.getValue() + "]\n" );
       }
     }
     interateHash.putAll( mailNicknameHash );
     if ( plog.isTraceEnabled() ) {
       plog.trace( "interateHash" );
       for ( Map.Entry entry : interateHash.entrySet() ) {
         plog.trace( "ARL-UMNN-004 [" + entry.getKey() + ", " + entry.getValue() + "]\n" );
       }
     }
     List foundNames = new ArrayList();
     Object azureNames = isAzureMailNicknamePresent( context, app, mailNicknameHash );
     if ( plog.isTraceEnabled() ) {
       plog.trace( "ARL-UMNN-005 azureNames Class: " + azureNames.getClass().getName() );
     }
     IdentityService is = new IdentityService(context);
     Application app = context.getObjectByName(Application.class, "Azure AD");
     List oldNickNames = new ArrayList();
     List links = is.getLinks(identity, app);
     for (Link link : links){
       if (link != null && link.getAttribute("proxyAddresses")!= null){
        List proxyAddresses = link.getAttribute("proxyAddresses");
        for(String proxyAddress : proxyAddresses){
          if (proxyAddress!= null){
            oldNickNames.add( proxyAddress.split( ":" )[ 1 ].split( "@" )[ 0 ] );
          }
        }
       }
     }
     if ( azureNames != null && azureNames.size() > 0 ) {
       foundNames.addAll( azureNames );
       if ( plog.isTraceEnabled() ) {
         plog.trace( "ARL-UMNN-006 foundNames 1: " + foundNames.toString() );
       }
     } else {
       if ( plog.isTraceEnabled() ) {
         plog.trace( "ARL-UMNN-007 no list from Azure" );
       }
     }

     Object sailPointNames = isSailPointMailNicknamePresent( context, mailNicknameHash );
     if ( plog.isTraceEnabled() ) {
       plog.trace( "ARL-UMNN-008 sailPointNames Class: " + sailPointNames.getClass().getName() );
     }

     if ( sailPointNames != null && sailPointNames.size() > 0 ) {
       foundNames.addAll( sailPointNames );
       if ( plog.isTraceEnabled() ) {
         plog.trace( "ARL-UMNN-009 foundNames 1: " + foundNames.toString() );
       }
     } else {
       if ( plog.isTraceEnabled() ) {
         plog.trace( "ARL-UMNN-010 no list from SailPoint" );
       }
     }

     for ( Map.Entry entry : interateHash.entrySet() ) {
       if ( entry != null ) {
         String entryValue = entry.getValue();
         if ( entryValue != null ) {
           for ( String usedNickname : foundNames ) {
             if ( entryValue.equalsIgnoreCase( usedNickname ) &&  !oldNickNames.contains(usedNickname)) {
               mailNicknameHash.remove( entry.getKey() );
             }
           }
         }
       }
     }

     if ( startNumber == 0 ) {
       startNumber = 1;
     } else {
       startNumber = startNumber + 5;
     }
   } while ( mailNicknameHash.isEmpty() );

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-UMNN-011 Exiting Attribute Rule Library - uniqueMailNickname" );
     plog.trace( msgSeparator );
   }

   return mailNicknameHash.firstEntry().getValue().toString();
 }

 /*******
 return email/upn domain suffix
  *******/
 public String getDomainSuffix( SailPointContext context, Application application ) {
   String domainSuffix = "";

   Map domainMails = new HashMap();
   mailDomains = application.getAttributeValue( "emailDomainNames" ) != null ? application.getAttributeValue( "emailDomainNames" ) : null;

   if ( mailDomains != null ) {
     for ( Map.Entry emailDomainEntry : mailDomains.entrySet() )  {
       String emailDomain = emailDomainEntry.getKey();
       String emailDomainPriority = emailDomainEntry.getValue();

       if ( emailDomainPriority.equalsIgnoreCase( "primary" ) ) {
         domainSuffix = emailDomain;
       }
     }
   }
   return domainSuffix;
 }

 /*******
 return updated proxyAddresses
 *******/
 public List getProxyAddresses( SailPointContext context, Identity identity ) {

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GPA-001 Under getProxy Address" );
   }
   String emailProxyAddress = "";
   emailProxyAddress = getIdentityAttribute( context, identity, "userPrincipalName" );
   // emailProxyAddress = emailProxyAddress.isEmpty() ? "" : "SMTP:" + emailProxyAddress; // isEmtpy on null object was creating problem, commented

   if (null != emailProxyAddress && !emailProxyAddress.isEmpty()) {
     emailProxyAddress= "SMTP:" + emailProxyAddress;
   }
   else {
   emailProxyAddress="";
   }
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GPA-002 Under getProxy Address emailProxyAddress"+emailProxyAddress );
   }

   List proxyAddresses = new ArrayList();
   proxyAddresses = getApplicationAttribute( context, identity, "Active Directory - NA",  "proxyAddresses" );

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GPA-003 Under getProxy Address proxyAddresses"+proxyAddresses );
   }

   List newProxyAddresses = new ArrayList();

   if ( proxyAddresses == null ) {
     if ( !emailProxyAddress.isEmpty() ) {
       newProxyAddresses.add( emailProxyAddress );
     }
   } else {

     for ( String address : proxyAddresses ) {
       if(address==null){
         continue;
       }
       newProxyAddresses.add( address.toLowerCase() );
     }
     if ( newProxyAddresses.contains( emailProxyAddress.toLowerCase() ) ) {
       newProxyAddresses.remove( emailProxyAddress.toLowerCase() );
     }
     newProxyAddresses.add( emailProxyAddress );
   }

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GPA-004 return proxyAddresses"+newProxyAddresses );
   }
   return newProxyAddresses;
 }

 /*******
 remove attribute change from Azure Sync enabled users for attributes that are contained in the sync configuration
  *******/
 public Object disallowAzureUpdateForOnPremSync( SailPointContext context, AttributeTarget target, Object value, Link link ) {
   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-DAUOPS-001 Entering Attribute Rule Library - disallowAzureUpdateForOnPremSync" );
   }

   Object newAttributeValue = null;

   if ( link != null && target != null ) {
     Boolean isDirSyncEnabled = link.getAttribute( "dirSyncEnabled" ) != null ? link.getAttribute( "dirSyncEnabled" ) : false;
     String azureAttributeName = target.getName() != null ? target.getName() : "";
     Application application = target.getApplication();
     String applicationName = application != null ? application.getName() : "";
     String nativeIdentity = link.getNativeIdentity() != null ? link.getNativeIdentity() : "";
     newAttributeValue = link.getAttribute(azureAttributeName);
     if ( isDirSyncEnabled ) {
       if ( plog.isTraceEnabled() ) {
         plog.trace( "ARL-DAUOPS-002 The account " + nativeIdentity + " is dirSyncEnabled" );
       }

       if ( applicationName.startsWith( "Azure" ) ) {

         Map azureSyncAttributeMap = application != null ? application.getAttributeValue( "onPremSyncAttributes" ) : null;

         if ( azureSyncAttributeMap != null ) {
           if ( !azureSyncAttributeMap.containsKey( azureAttributeName ) ) {
             if ( plog.isTraceEnabled() ) {
               plog.trace( "ARL-DAUOPS-003 Allowing update to Azure Attribute for " + azureAttributeName );
             }
             newAttributeValue = value;
           } else {
             if ( plog.isTraceEnabled() ) {
               plog.trace( "ARL-DAUOPS-004 Disallowing update to Azure Attribute for " + azureAttributeName );
             }
           }
         } else {
           plog.error( "ARL-DAUOPS-005 Cannot get Azure Directory Sync attribute list." );
         }
       } else {
         plog.error( "ARL-DAUOPS-006 Cannot Use disallowAzureUpdateForOnPremSync Rule with Application: " + applicationName );
       }

     } else { // if the account is not Directory Sync Enabled process the update
       if ( plog.isTraceEnabled() ) {
         plog.trace( "ARL-DAUOPS-007 The account " + nativeIdentity + " is not dirSyncEnabled" );
         plog.trace( "ARL-DAUOPS-008 Attribute " + azureAttributeName + " is being updated in " + applicationName );
       }
       newAttributeValue = value;
     }
   }

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-DAUOPS-009 Exiting Attribute Rule Library - disallowAzureUpdateForOnPremSync" );
     plog.trace( msgSeparator );
   }

   return newAttributeValue;
 }

