 /*******
 generate a displayname for employees
 The method also generates the displayname for supplier where pronoun will be utilizing the primary supplier number and companyCode will use Supplier value
  *******/
 public String generateDisplayname( SailPointContext context, String firstname, String lastname, String middlename, String companyCode, String pronoun ) {
   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-GDN-001 Entering Attribute Rule Library - generateDisplayname" );
   }

   String displayName;
   String compAbbreviation = null;

   Custom companyObj = context.getObjectByName( Custom.class, "Company Name Mappings" );
   if (Util.isNotNullOrEmpty( companyCode )){
     compAbbreviation = companyObj.get( companyCode.trim() );
   }
   if (null != middlename && !middlename.equalsIgnoreCase("null") && !middlename.trim().equals("")) {
     displayName = firstname + " "+middlename+ " " + lastname;
   }
   else {
   displayName = firstname + " " + lastname;
   }

   if ( Util.isNotNullOrEmpty( pronoun ) ) {
     displayName = displayName + " (" + pronoun + ")";
   }

   if ( compAbbreviation != null && compAbbreviation.length() > 0 ) {
     displayName = displayName + " (" + compAbbreviation + ")";
   }

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GDN-002 Exiting Attribute Rule Library - generateDisplayname.  Generated Displayname:: " + displayName );
     plog.trace( msgSeparator );
   }

   return displayName;
 }

 /*******
 Check if a Identity is MTM subType or not
*******/
 public boolean checkNonMTMUser(SailPointContext context, Identity identity){
   Object subTypeObj = identity.getAttribute("subType");
   String companyCode = identity.getAttribute("companyCode");
   boolean returnBol = false;

   if(subTypeObj != null){
     if(subTypeObj instanceof List){
       if(Util.nullSafeContains(subTypeObj,"MTM")){
         returnBol = true;
       }
     }else if(subTypeObj instanceof String){
       if(Util.nullSafeCaseInsensitiveEq(subTypeObj,"MTM")){
         returnBol =  true;
       }
     }
   }else if(Util.nullSafeCaseInsensitiveEq(companyCode,"MTM")){
       returnBol = true;
   }
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-CNMTMU-001 Exiting Attribute Rule Library - CheckNonMTMUser.  Generated boolean:: " + returnBol );
     plog.trace( msgSeparator );
   }
   return returnBol;
 }

