     plog.trace( "ARL-GMCA-001: Entering Attribute Rule Library - getModifiedContactAssignment for identity " +identity+ ", contact assignment " +conAssignAttrName);
   }
   List updatedList = new ArrayList();
   List conAssignVals = Util.filterNulls(Util.asList(identity.getAttribute(conAssignAttrName)));
