   return updatedList;
 }

 /*******
   Generate Supplier User Plant Details with '#' seperator
   This will generate a list of plant details like "plantCode#definitionCode#definitionDesc" for a supplier user
 *******/
 public static List supplierUserPlantDetails( SailPointContext context, Identity identity ) {
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-SUPD-001: Entering Attribute Rule Library - supplierUserPlantDetails for identity " +identity);
   }
   List finalList = new ArrayList();
   finalList.addAll(ListUtils.emptyIfNull(getModifiedContactAssignment(identity,"CONTACT_ASSIGNMENT_35","#35#Plant Manager")));
