   finalList.addAll(ListUtils.emptyIfNull(getModifiedContactAssignment(identity,"CONTACT_ASSIGNMENT_46","#46#Executive")));
   finalList.addAll(ListUtils.emptyIfNull(getModifiedContactAssignment(identity,"CONTACT_ASSIGNMENT_138","#138#Ordering Emergency Contact")));
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-SUPD-002: Final list: " + finalList);
   }
   return finalList;
 }
 /*******
 generate an expirationDate for contractors
 *******/
 public String getContractorExpirationDate() {
   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-GCED-001 Entering Attribute Rule Library - getContractorExpirationDate" );
   }
   String expirationDate = "";
   DateFormat dateFormat = new SimpleDateFormat("MM/dd/yyyy HH:mm:ss a z");
   Calendar calendar = Calendar.getInstance();
   Date currentDate = calendar.getTime();
   calendar.add(Calendar.YEAR, 1);
   Date nextYear = calendar.getTime();
   nextYear = Util.getEndOfDay(nextYear);
   expirationDate = dateFormat.format(nextYear);
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GCED-002 Exiting Attribute Rule Library - getContractorExpirationDate :: "+expirationDate);
   }
   return expirationDate;
 }


