 /*******
 Convert Date to AD date format
 *******/
 public String convertDateToAD( String humanDate ) {
   Long adTimestamp = null;
   String adDate = "";
   SimpleDateFormat sdf = new SimpleDateFormat( "MM/dd/yyyy");
   if(Util.isNotNullOrEmpty(humanDate))
   {
     if (humanDate != null && humanDate.contains("/")) {
       if (humanDate.contains(":")) {
         sdf = new SimpleDateFormat("MM/dd/yyyy HH:mm:ss");
       } else {
         sdf = new SimpleDateFormat("MM/dd/yyyy");
       }
     } else if(humanDate != null && humanDate.contains("-")) {
       if (humanDate.contains(":")) {
         sdf = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss");
       } else {
         sdf = new SimpleDateFormat("yyyy-MM-dd");
       }
     }
     Date date = sdf.parse( humanDate );
     if ( plog.isTraceEnabled() ) {
       plog.trace( "ARL-CDTAD-001 Date is " + date );
     }
     if ( date != null) {
       date = Util.getEndOfDay(date);
       adTimestamp = ( date.getTime()*10000L ) + 116444736000000000L;
     }
     if ( adTimestamp != null ) {
       if ( plog.isTraceEnabled() ) {
         plog.trace( "ARL-CDTAD-002 AD Timestamp is: " + adTimestamp );
       }
       adDate = adTimestamp.toString();
     }
   }
   else
   {
     if ( plog.isTraceEnabled() ) {
       plog.trace( "ARL-CDTAD-003 Input human date for AD conversion is empty: "  );
     }
   }
   return adDate;
 }

 /*******
  Calculate ExpirationDate based on HireDate at the time of Identity Creation
  If HireDate exists then HireDate+1year, if not currentDate+1year
 *******/
 public String getExpirationDateFromHireDate( String hireDate ) {
   DateFormat dateFormat =null;
   if (hireDate != null && hireDate.contains("/")) {
     if (hireDate.contains(":")) {
       dateFormat = new SimpleDateFormat("MM/dd/yyyy HH:mm:ss");
     } else {
       dateFormat = new SimpleDateFormat("MM/dd/yyyy");
     }
   } else if(hireDate != null && hireDate.contains("-")) {
     if (hireDate.contains(":")) {
       dateFormat = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss");
     } else {
       dateFormat = new SimpleDateFormat("yyyy-MM-dd");
     }
   }
   String expirationDate = null;
   if(hireDate != null && !hireDate.isEmpty()){
     try
     {
     Date dtHireDate = dateFormat.parse(hireDate);
     Calendar calendar = Calendar.getInstance();
     calendar.setTime(dtHireDate);
     calendar.add(Calendar.YEAR, 1);
     Date dtExpirationDate = calendar.getTime();
     dtExpirationDate = Util.getEndOfDay(dtExpirationDate);
     expirationDate = dateFormat.format(dtExpirationDate);
     }catch(Exception parseExp)
     {
      plog.error("ARL-GEDHD-001 getExpirationDateFromHireDate failed with error: " +parseExp.getMessage());
      return null;
     }
   }
   else{
     expirationDate = getContractorExpirationDate();
   }
   return expirationDate;
 }

