 /*
 This methord returns the domain name of the account from the native identity. 
   To be used to fetch the right userContainer in application xml.
   All domain name will be returned in upper case.
 */
 public String getDomainNameFromNativeIdentity(String adNativeIdentity)
 {
   int adIndex = adNativeIdentity.toUpperCase().indexOf("DC");
   String lnkDomain = null;
   if (adIndex > 0)
   {
     String[] adNativeSplit = adNativeIdentity.substring(adIndex + 3).split(",");
     if (adNativeSplit.length > 1)
     {
       lnkDomain = adNativeSplit[0].toUpperCase();
     }
   }
   return lnkDomain;
 } 
 /*******
 return native identity of primary AD account
 If the user has multiple accounts the primary account is in the user container
 *******/
 public String getADPrimaryAccountDN( SailPointContext context, Identity identity, Application application ) {

   plog.trace( "ARL-GADPADN-001 Entering Attribute Rule Library - getADPrimaryAccountDN" );
   String primaryADNativeIdentity = "";
   String userContainer = "";
   Map accountContainers = null;

   Map accountContainersKey = application.getAttributeValue( "userContainers" );
   Set accountContainersKeySet = accountContainersKey.keySet();
   for ( String key : accountContainersKeySet ) {
     accountContainers = accountContainersKey.get(key);
   }

   if ( accountContainers != null && !accountContainers.isEmpty() && accountContainers.containsKey( "users" ) ) {
     userContainer = accountContainers.get( "users" ).toUpperCase();
   } else {
     plog.error( "ARL-GADPADN-002 Cannot retrieve userContainer for Application: " + application.getName() );
   }

   if ( userContainer != null && !userContainer.isEmpty() ) {
     IdentityService identityService = new IdentityService( context );
     List adLinks = identityService.getLinks( identity, application );

     if ( adLinks !=null && !adLinks.isEmpty() ) {
       for ( Link adLink : adLinks ) {

         String linkNativeIdentity = adLink.getNativeIdentity();
         if ( linkNativeIdentity != null && !linkNativeIdentity.isEmpty() && linkNativeIdentity.toUpperCase().indexOf( userContainer ) > 0 ) {
           primaryADNativeIdentity = linkNativeIdentity;
         }
       }
     } else {
       plog.error( "ARL-GADPADN-003 Identity: " + identity.getName() + " does not have and account in " + application.getName() );
     }
   }

   primaryADNativeIdentity = primaryADNativeIdentity != null ? primaryADNativeIdentity : "";
   plog.trace( "ARL-GADPADN-004 Exiting Attribute Rule Library - getADPrimaryAccountDN" );
   return primaryADNativeIdentity;
 }

