 public Object getADPrimaryAccountAttribute ( SailPointContext context, Identity identity, String applicationName, String userContainer, String attributeName ){
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GADPAA-001 Entering Attribute Rule Library - getADPrimaryAccountAttribute with values:" );
     plog.trace( "ARL-GADPAA-002 identity: "+identity.getName() );
