 public ProvisioningPlan examinePlan(ProvisioningPlan plan, String applicationName){
   AccountRequest accReq=plan.getAccountRequest(applicationName);
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-EP-001 Inside examinePlan()");
     plog.trace( "ARL-EP-002 appName: \n" + applicationName );
     plog.trace( "ARL-EP-003 plan \n" + plan.toXml() );
   }
   Custom appAttrCustomObject = context.getObjectByName( Custom.class, "Application Attributes Never Empty" );

   if (accReq.getOperation().toString().equals("Modify") ) {
     if ( plog.isTraceEnabled() ){
       plog.trace( "ARL-EP-004 inside modify: \n" );
     }
     if ( appAttrCustomObject != null ) {
       if ( plog.isTraceEnabled() ){
         plog.trace( "ARL-EP-005 Application Attributes Never Empty: \n" + appAttrCustomObject.toString() );
       }
       Map appAttrMap = appAttrCustomObject.get( "Application Attributes Never Empty" );
       List attrList=appAttrMap.get(applicationName);
       if ( attrList != null && !attrList.isEmpty() ) {
         if ( plog.isTraceEnabled() ) {
           plog.trace( "ARL-EP-006 Attributes that cannot be null: \n" + attrList.toString() );
         }
         List attributeRequestsToRemove=new ArrayList();
         for(AttributeRequest attrRequest:accReq.getAttributeRequests()){
           if (attrList.contains(attrRequest.getName())) {
             if (attrRequest.getValue()==null || attrRequest.getValue().toString().isEmpty()){
               if ( plog.isTraceEnabled() ) {
                 plog.trace("ARL-EP-007 Detected an AttributeRequest to set " + attrRequest.getName() + " as null. Removing it:\n" + plan.toXml());
               }
               attributeRequestsToRemove.add(attrRequest);
             }
           }
         }
         if ( attributeRequestsToRemove != null && attributeRequestsToRemove.size() > 0 ) {
           for ( AttributeRequest attrRequest : attributeRequestsToRemove ) {
             if ( plog.isTraceEnabled() ){
               plog.trace( "ARL-EP-008 Removing Attribute Request: " + attrRequest.toXml() );
             }
             accReq.remove( attrRequest );
           }
         }
       }
     }
   }
   if ( plog.isTraceEnabled() ) {
     plog.trace("#####################################################");
     plog.trace( "ARL-EP-009 Plan After Deletion:\n" + plan.toXml() );
   }
   return plan;
 }

 /*******
   Generate AD Privileged DN
   This will generate a DN for a new AD Privileged account
   TODO: Update logic to select 
     1) Forest 
     2) Container
     3) cn attribute
 *******/  

 public static String generatePrivilegedADDN( SailPointContext context, Identity identity, Application application ) {
   if ( plog.isTraceEnabled() ) {
     plog.trace( msgSeparator );
     plog.trace( "ARL-GPADDN-001 Entering Attribute Rule Library - generatePrivilegedADDN" );
   }

   Map forestContainers = application.getAttributeValue( "userContainers" );

   String privilegedADDN = "";
   String targetDomain = "";
   String userContainer = "privileged";
   String accountAttribute = "workday_id";

   if ( forestContainers != null && !forestContainers.isEmpty() ) {

     plog.trace( "forestContainers:\n" + forestContainers.toString() );

     if ( forestContainers.containsKey( "MTMUSTEST" ) ) {
       targetDomain = "MTMUSTEST";
     } else if ( forestContainers.containsKey( "TMMTEST" ) ) {
       targetDomain = "TMMTEST";
     } else if ( forestContainers.containsKey( "TMM" ) ) {
       targetDomain = "TMM";
     } else if ( forestContainers.containsKey( "MTMUS" ) ) {
       targetDomain = "MTMUS";
     }
     else if ( forestContainers.containsKey( "ENGTEST" ) ) {
       targetDomain = "ENGTEST";
     }
     else if ( forestContainers.containsKey( "ENG" ) ) {
       targetDomain = "ENG";
     }
     Map domainContainers = forestContainers.get( targetDomain );
     String baseDN = domainContainers.get( userContainer );

     String workdayID = identity.getAttribute( accountAttribute );
     if(targetDomain.contains("ENG")){
       privilegedADDN = "CN=" + application.getAttributeValue("adPrivAccountPrefix")+"-"+workdayID + "," + baseDN;
     }
     else{
       privilegedADDN = "cn=" + application.getAttributeValue("adPrivAccountPrefix")+"-"+workdayID + "," + baseDN;
     }
     if ( plog.isTraceEnabled() ) {
       plog.trace( "ARL-GPADDN-002 User distingushedName: " + privilegedADDN );
     }
   }

   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GPADDN-003 Exiting Attribute Rule Library - generatePrivilegedADDN" );
     plog.trace( msgSeparator );
   }

   return privilegedADDN;
 }

 // Method to send email notification. Used in Active Directory NA - Afterprovisioningrule

 public void sendEmailNotification(String toAddress, String emailTemplate, String userName, String requesterName, List mapList) {
   try {
     if(!Util.isAnyNullOrEmpty(toAddress,emailTemplate,userName,requesterName)) {
       plog.trace("ARL-SEN-001 Rule Name : Toyota AD AfterProvisioningRule , Method Name : sendEmailNotification ,Inside if Statement ");
       EmailTemplate template = context.getObjectByName(EmailTemplate.class, emailTemplate);
       EmailOptions options = new EmailOptions();
       options.setTo(toAddress);
       Map args = new HashMap();
       args.put("mapList", mapList);
       args.put("requesterName", requesterName);
       args.put("userName", userName);
       options.setVariables(args);
       options.setSendImmediate(true);
       context.sendEmailNotification(template, options);
     }
   } catch (GeneralException e) {
     plog.error("ARL-SEN-002 Rule Name : Toyota AD AfterProvisioningRule , Method Name : sendEmailNotification ,erro : "+e.getMessage());
   }
 }

 //Method to get updated UPN for Priv

 public static String getUPNNonPrivValue(SailPointContext context, Identity identity, String samAccountName,
   String distinguishedName, Application application) {
   plog.trace("ARL-GUPNPV-001 ::" + msgSeparator);
   plog.trace("ARL-GUPNPV-002 ::Entering Attribute Rule Library - getUPNNonPrivValue");
   plog.trace("ARL-GUPNPV-003 ::samAccountName: " + samAccountName);
   plog.trace("ARL-GUPNPV-004 ::distinguishedName: " + distinguishedName);

   String upnPrefix;
   String upnDomainSuffix;
   String nativeIdentity;

   String upn = getIdentityAttribute(context, identity, "userPrincipalName");
   plog.trace("ARL-GUPNPV-006 :: Identity " + identity.getName() + " userPrincipalName: " + upn);
   String samAccountName = samAccountName;
   String updatedUpn = null;
   String domainKey;
   try {
     if (Util.isNotNullOrEmpty(upn)) {
       if (!validateEmail(upn)) {
         plog.trace("ARL-GUPNPV-007 :: UPN not valid format :: " + upn + " for Identity Name :: " + identity.getName());
       } else {
         upnPrefix = upn.split("@")[0];
         upnDomainSuffix = upn.split("@")[1];
         nativeIdentity = distinguishedName;
         domainKey = nativeIdentity.toUpperCase().split(",DC=")[1];
         updatedUpn = upnPrefix + "@" + upnDomainSuffix;
         plog.trace("ARL-GUPNPV-009 :: Account setting UPN for " + nativeIdentity + " to: " + updatedUpn);

         Map domainSuffixMap = application.getAttributeValue("domainSuffixMap");
         String workGroupName = application.getAttributeValue("lexusWorkGroupName");
         String identityName = identity.getName();
         boolean isLexusUpn = false;
         if (Util.isNotNullOrEmpty(workGroupName)) {
           isLexusUpn = isUserMemberOfWorkGroup(workGroupName, identityName);
         }
         if (domainSuffixMap != null && !domainSuffixMap.isEmpty() && Util.isNotNullOrEmpty(domainKey)
             && domainSuffixMap.containsKey(domainKey)) {
           if (isLexusUpn) {
             domainKey = application.getAttributeValue("lexusDomainKey");
           }
           upnDomainSuffix = domainSuffixMap.get(domainKey);
           updatedUpn = upnPrefix + upnDomainSuffix;
           plog.trace("ARL-GUPNPV-010 ::Correcting Domain Suffix. Setting UPN for " + nativeIdentity + " to: " + updatedUpn);
         } else {
           plog.error("ARL-GUPNPV-011 ::error getting AD Domain Suffix for Domain Key: " + domainKey+ " For Identity: " + identity.getName());
         }
       }
     }
   }catch (Exception e) {
     plog.error("ARL-GUPNPV-012 :: " + e.getClass().getName() + " Exception happened ::" + e + " For Identity Name :: "+ identity.getName() + " and UPN ::" + upn);
     throw new Exception("ARL-GUPNPV-013 :: Exception happened  " + e + " For Identity Name :: " + identity.getName()+ " and UPN ::" + upn);
   }
   plog.trace("ARL-GUPNPV-014 ::" + updatedUpn);
   return updatedUpn;
 }

