 //Generate Proxy address for newly created AD account

 public List generateProxyAddresses( SailPointContext context, Identity identity, String distinguishedName, Application application, boolean isPrivilegedAccount ) 
 {
   String proxyAddress;
   String nativeIdentity = distinguishedName ;
   Map domainSuffixMap = application.getAttributeValue( "domainSuffixMap" );

   String workdayID = getIdentityAttribute(context, identity, "workday_id");
   List proxyAddressess = new ArrayList();

   if ( isPrivilegedAccount ) 
   {
     plog.trace( "ARL-GPA-001 No Proxy Address for Privileged Account " + nativeIdentity );
     proxyAddress = "";
     proxyAddressess.add(proxyAddress);
   } else
   {
     String domainKey = nativeIdentity.toUpperCase().split(",DC=")[1];

     if (domainKey!=null && (Util.nullSafeCaseInsensitiveEq(domainKey, "tmm") || Util.nullSafeCaseInsensitiveEq(domainKey, "tmmtest")))
     {
       domainKey = domainKey;
     } else 
     {
       plog.trace( "ARL-GPA-002 No Proxy Address for non-tmm DN based Account " + nativeIdentity );

       proxyAddress = ""; // for non-tmm domain
       proxyAddressess.add(proxyAddress);
     }

     if ( domainSuffixMap != null && !domainSuffixMap.isEmpty() &&  domainSuffixMap.containsKey( domainKey )) 
     {        
       String EnvDomain = domainSuffixMap.get( domainKey );
       proxyAddress = "smtp:"+workdayID+EnvDomain;
       plog.trace( "ARL-GPA-003 Setting Proxy Address for Account " + nativeIdentity + " to: " + proxyAddress );

       proxyAddressess.add(proxyAddress); 
     }
   }
   return proxyAddressess;
 }

 /**
   * launchEmailChangeWorkflow to Calculate EmailChange based on attribute change FirstName, LastName. 
   * @param oldValue a HashMap containing the old attribute Values
   * @param newValue a HashMap containing the new attribute values
   * @param triggererName holds value of the attribute changed.
   * @return workFlow Id to be Launched
   * Calling the workflow via request to call after 10 mins as we need to set email first if missing and then set email arguments
 */
 public String launchEmailChangeWorkflow(Identity identity, String triggererName, String oldValue,String newValue) {

   plog.trace("ARL-LECWF-001 Entring launch Email Change Workflow");

   String workflowName = "Workflow-Lifecycle-EmailChange";
   String caseName = "Email Change for Identity: "+identity.getName();
   String requesterId = "spadmin";
   Workflow eventWorkflow = context.getObject(Workflow.class, workflowName);
   Identity id = context.getObjectByName(Identity.class, requesterId);
   DateFormat dateFormat = new SimpleDateFormat("MM/dd/yyyy");
   Calendar calendar = Calendar.getInstance();
   calendar.add(Calendar.MINUTE, 10);
   Date futureTime = calendar.getTime();
   String launchTime = dateFormat.format(futureTime);

   caseName = caseName + "(" + launchTime + ")";
   Attributes reqArgs = new Attributes();
   reqArgs.put(StandardWorkflowHandler.ARG_REQUEST_DEFINITION, sailpoint.request.WorkflowRequestExecutor.DEFINITION_NAME);
   reqArgs.put(sailpoint.workflow.StandardWorkflowHandler.ARG_WORKFLOW, workflowName);
   reqArgs.put(sailpoint.workflow.StandardWorkflowHandler.ARG_REQUEST_NAME, caseName);
   reqArgs.put( "requestName", caseName );
   Attributes wfArgs = new Attributes();

   wfArgs.put("identityName", identity.getName());
   wfArgs.put("triggererAttribute", triggererName);
   wfArgs.put("launcher", "spadmin");
   wfArgs.put("oldValue", oldValue);
   wfArgs.put("newValue", newValue);
   wfArgs.put("workflow", eventWorkflow.getName());

   plog.trace("ARL:0011 : worklfow arguments " +wfArgs);

   reqArgs.putAll(wfArgs);
   Request req = new Request();
   RequestDefinition reqdef = context.getObject(RequestDefinition.class, "Workflow Request");
   req.setDefinition(reqdef);
   req.setEventDate(futureTime);
   req.setOwner(id);
   req.setName(caseName);
   req.setAttributes( reqdef, reqArgs );
   RequestManager.addRequest(context, req);

   plog.trace("ARL-LECWF-004 Ending launch Email Change Workflow");

   return "Launched Workflow-Lifecycle-EmailChange successfully";
 }

 public boolean updateAzureUserEmailAttributes(SailPointContext context, Application application,AccountRequest accountRequest, Identity identity) {
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-UPAUEA-001 Inside Update Azure Email Attribute "  );
   }
   List emailGroups = application.getAttributeValue( "emailGroups" );
   boolean updated = true;
   /***
   TODO
   not sure if we can do this because of bad data but ideally we wouldn't even bother to check the groups
   if the user already has an email.  To do this we would need to make sure that the fake email in Azure
   neven got into SailPoint
   String userEmail = identity.getEmail();
   ***/
   // Only evaluate attributeRequests if there are group requests in the accountRequest
   List groupAttributeRequests = accountRequest.getAttributeRequests( "groups" );
   if ( groupAttributeRequests != null && !groupAttributeRequests.isEmpty() ) {
     for (AttributeRequest planattributes: groupAttributeRequests ) {
       String aroperation = planattributes.getOperation().toString();
       String arname = planattributes.getName().toString();

       Object arvalue = planattributes.getValue();
       String upn = identity.getAttribute( "userPrincipalName" );
       // only check if a group is being requested that may add email
       if ( aroperation.equals("Add") && Util.nullSafeCaseInsensitiveEq( arname, "groups" ) ) {
         // check for adding of group that provides mailbox
         boolean emailRequest = false;
         if ( arvalue != null && emailGroups !=null && !emailGroups.isEmpty() ) {
           if ( arvalue instanceof List ) {
             for ( String emailGroup : emailGroups ) {
               if ( arvalue.contains( emailGroup ) ) {
                 emailRequest = true;
               }
             }
           } else if ( arvalue instanceof String ) {
             if ( emailGroups.contains( arvalue ) ) {
               emailRequest = true;
             }
           } else {
             plog.error( "ARL-UPAUEA-002 Error with Azure Provisioning Plan.  Group Attribute is of type: " + arvalue.getClass().getName() + " for Identity: " + identity.getName() );
           }
         }
         if ( emailRequest ) {
           if (plog.isTraceEnabled()) {
             plog.trace("=====Inside Group condition=======");
           }

           String userWorkdayId = identity.getAttribute( "workday_id" );
           plog.trace("ARL-UAUEA-003 user's current workday id is: "+userWorkdayId);

           boolean updateUPN = false;
           if (null != upn && upn.startsWith(userWorkdayId)) {
             plog.trace("Current UPN of user contains workday id. Generating new UPN for user");              
             Map identityNameData = getIdentityNameData( context, identity );
             if ( plog.isTraceEnabled() ) {
               plog.trace( "ARL-UAUEA-004 Name Data for Identity: " + identity.getName() + " :: " + identityNameData.toString() );
             }
             String firstname = identityNameData.get( "firstname" );
             String lastname = identityNameData.get( "lastname" );
             String middlename = identityNameData.get( "middlename" );
             String mailNickname = uniqueMailNickname( context, application, firstname, lastname, middlename, identity );
             String domainSuffix = upn.split( "@" )[1];
             upn = mailNickname + "@" + domainSuffix;

             plog.trace( "ARL-UAUEA-005 New UPN for Identity: " + identity.getName() + " is: " + upn );
             updateUPN = true;
           }

         //Set email to the user
           email= upn;
           String identityName = identity.getName();
           ProvisioningPlan provisioningPlan = new ProvisioningPlan();
           provisioningPlan.setIdentity(identity);

           AccountRequest accountRequest = new AccountRequest();
           accountRequest.setApplication(ProvisioningPlan.APP_IIQ);
           accountRequest.setOperation(AccountRequest.Operation.Modify);
           accountRequest.setNativeIdentity(identityName);

           AttributeRequest attributeRequest = new AttributeRequest();
           attributeRequest.setName("email");
           attributeRequest.setOp(Operation.Set);
           attributeRequest.setValue (email);
           accountRequest.add(attributeRequest);

           // if we had to generate a new UPN because the user had a WDID UPN update it as well as email
           if ( updateUPN ) {
             AttributeRequest upnAR = new AttributeRequest();
             upnAR.setName( "userPrincipalName" );
             upnAR.setOp( Operation.Set );
             upnAR.setValue( upn );
             accountRequest.add( upnAR );
           }

           provisioningPlan.add(accountRequest);

           if ( plog.isTraceEnabled() ) {
             plog.trace("ARL-UAUEA-006 Provisioning Plan for " + identityName +" : "+ provisioningPlan.toXml());
           }
           Provisioner provisioner=new Provisioner(context);
           provisioner.execute(provisioningPlan);
           if ( plog.isTraceEnabled() ) {
             plog.trace("=====Launching Email Change Workflow=======");
           }
           String workflowCase = launchEmailChangeWorkflow(identity, "email", "", email);

         }
       } else {
         updated=false;
         plog.error("ARL-UAUEA-007 Email group is either NULL or Empty");
       }
     }
   }
   return updated;
 }


 public boolean isUserMemberOfWorkGroup(String workGroupName, String identityName) {
   boolean userIsMemberOfWorkGroup=false;
   try {
     if( Util.isNotNullOrEmpty(workGroupName) && Util.isNotNullOrEmpty(identityName) ) {
       Identity wgIdenObj = context.getObjectByName(Identity.class, workGroupName);
       Identity userIdenObj = context.getObjectByName(Identity.class, identityName);
       if( wgIdenObj != null && userIdenObj != null ) {
         userIsMemberOfWorkGroup = userIdenObj.isInWorkGroup( wgIdenObj );
         if ( userIsMemberOfWorkGroup ) {
           plog.trace( "ARL-IUMWG-001 Identity: " + identityName + " is in WorkGroup " + workGroupName );
         } else {
           plog.trace( "ARL-IUMWG-002 Identity: " + identityName + " is in WorkGroup " + workGroupName );
         }
       }
     }
   }catch(GeneralException e) {
     plog.error( "ARL-IUMWG-003 error while checking if user part of workgroup");
   }
   return userIsMemberOfWorkGroup;
 }

 public List getAuthoritativeDomains() {
   // We are defining "Authoritative" as either:
   //  1) We generate and maintain the UPN
   // or
   //  2) We have an Active Directory source for the UPN of the user
   Filter appFilter = Filter.eq( "type", "Azure Active Directory" );

   QueryOptions qo = new QueryOptions();
   qo.addFilter( appFilter );

   List attributesToInclude = new ArrayList();
   attributesToInclude.add( "id" );
   List authoritativeDomains = new ArrayList();
   Iterator it = context.search( Application.class, qo ,attributesToInclude);
   if ( it != null ) {
     while ( it.hasNext() ) {
       Object [] thisRecord = it.next();
       String appId = (String) thisRecord[0];
       Application adApp = context.getObjectById( Application.class, appId);

       List adDomains = adApp.getAttributeValue( "authoritativeDomains" );

       if ( adDomains != null && !adDomains.isEmpty() ) {
         authoritativeDomains.addAll( adDomains );
       }
     }
   }
   Util.flushIterator(it);
   return authoritativeDomains;
 }


 public String determineAzureUpnEmail( SailPointContext context, Identity identity, Application application, String spAttribute , String azureAttribute) {
   plog.trace( "ARL-DAUE-001::Entering Attribute Rule Library - determineAzureUpnEmail "); 
   String updatedAttrValue = "";

   String identityType = identity.getType();
   String identityName = identity.getName();
   String currentAttrValue = identity.getAttribute(spAttribute);
   plog.trace( "ARL-DAUE-002::identityType ="+identityType); 
   plog.trace( "ARL-DAUE-003::identityName ="+identityName); 
   plog.trace( "ARL-DAUE-004::currentAttrValue ="+currentAttrValue); 


   // Get Azure Application Links that the user may have
   IdentityService identityService = new IdentityService( context );
   List azureLinks = identityService.getLinks( identity, application );
   plog.trace( "ARL-DAUE-005::azureLinks ="+azureLinks); 

   GroupDefinition tMNAUsers = context.getObjectByName(GroupDefinition.class,"TMNA Users");

   QueryOptions qo = new QueryOptions();
   Filter adFilter = tMNAUsers.getFilter();
   qo.addFilter(adFilter);
   qo.add(Filter.eq("name", identity.getName()));
   int isTMNA = context.countObjects( Identity.class, qo );

   // only check if Azure is the source for UPN/Email for contractor and employee user types
   if ( Util.nullSafeCaseInsensitiveEq( identityType, "employee" ) || Util.nullSafeCaseInsensitiveEq( identityType, "contractor" ) ) {      
     // Process the links if we have any (and we should have at least 1)
     if ( azureLinks != null && !azureLinks.isEmpty() ) {
       List authoritativeDomains = getAuthoritativeDomains();
       plog.trace( "ARL-DAUE-006::authoritativeDomains ="+authoritativeDomains); 

       // We will get the member link with email assigned and a list of any other member links
       // if there are multiple member accounts the one with the email license should be primary
       Link savedLink;
       int savedScore;

       for ( Link azureLink : azureLinks ) {
         String userType = azureLink.getAttribute( "userType" );
         plog.trace( "ARL-DAUE-007::userType ="+userType); 
         int azureLinkScore = 0;

         if ( Util.nullSafeCaseInsensitiveEq( userType, "member" ) ) {
           // Only deal with member type accounts for finding the primary Azure account
           // If a member account is not linked there is a problem with it and we log and skip.  All linked accounts have an onPremises DN
           String onPremisesDistinguishedName = azureLink.getAttribute( "onPremisesDistinguishedName" );
           plog.trace( "ARL-DAUE-008::onPremisesDistinguishedName ="+onPremisesDistinguishedName); 

           if ( Util.isNotNullOrEmpty( onPremisesDistinguishedName ) ) {
             // We are dealing with at least an aditional directory Sync member account.  which is better?
             //  4a) TMNA user - use current UPN/Email
             //  4b) Managed Domain with email - use current UPN/Email
             //  3)  Unmanaged with email - use Azure UPN/Email
             //  2)  Managed without email - use current UPN/Email
             //  1)  Unmanaged without email - use Azure UPN/Email
             //  0a) No link with value - Use current UPN/Email.
             //  0b) Inactive Azure Account - Use current UPN/Email.

             // Check for existence of email account.  If email license exists the UPN is primary with any

             // Current Loop Account Information
             boolean azureHasEmail = checkAzureForEmailLicense(azureLink);
             plog.trace( "ARL-DAUE-008::azureHasEmail ="+azureHasEmail); 

             String azureDomainKey = onPremisesDistinguishedName.toUpperCase().split(",DC=")[1];
             plog.trace( "ARL-DAUE-010::azureDomainKey ="+azureDomainKey); 

             boolean azureIsManaged = false;

             boolean isDisabled = azureLink.isDisabled();

             if ( authoritativeDomains != null && authoritativeDomains.contains( azureDomainKey ) ) {
               azureIsManaged = true;
             }
             plog.trace( "ARL-DAUE-011::azureIsManaged ="+azureIsManaged); 

             // Score current Link value based on priority ranking criteria
             // If Azure account is disabled we'll ignore azurelinkScore and set to 0
             if ( isDisabled ) {
               azureLinkScore = 0;
             } else if ( isTMNA > 0 ) {
               azureLinkScore = 4;
             } else {
               if ( azureHasEmail && azureIsManaged ) {
                 azureLinkScore = 4;
               } else if ( azureHasEmail && !azureIsManaged ) {
                 azureLinkScore = 3;
               } else if ( !azureHasEmail && azureIsManaged ) {
                 azureLinkScore = 2;
               } else if ( !azureHasEmail && !azureIsManaged ) {
                 azureLinkScore = 1;
               } else {
                 azureLinkScore = 0;
               }
             }
             plog.trace( "ARL-DAUE-012::azureLinkScore ="+azureLinkScore); 
             plog.trace( "ARL-DAUE-013::savedLink = "+savedLink +" savedScore="+savedScore); 

             // Update savedLink and savedScore as compared
             if ( savedLink != null && savedScore != null ) {
               if ( azureLinkScore > savedScore ) {
                 // The current account is a better UPN than the saved one.  use it
                 savedLink = azureLink.clone();
                 savedScore = azureLinkScore;
                 plog.trace( "ARL-DAUE-014::savedLink = "+savedLink +" savedScore="+savedScore); 
               } else if ( azureLinkScore == 4 && savedScore == 4 ) {
                 // There is a problem.  We have 2 managed accounts with an email.  Notify of error
                 plog.trace( "ARL-DAUE-015::savedLink = "+savedLink +" savedScore="+savedScore); 
               }
             } else {
               // This is the first member Link found and we will save it
               savedLink = azureLink.clone();
               savedScore = azureLinkScore;
               plog.trace( "ARL-DAUE-016::savedLink = "+savedLink +" savedScore="+savedScore); 
             }

           } else {
             // This is a non-directorySync member account and we don't know what to do with it
             plog.error( "ARL-DAUE-017 Identity: " + identityName + " has a non-directorySync member Azure account: " + azureLink.getNativeIdentity() );
           }
         } else {
           // guest accounts can never be authoritative for UPN.  Ignore
           plog.trace( "ARL-DAUE-018 Ignoring Guest Account for user with multiple Azure accounts." );
         }
       } // END For Loop.  We should have our Primary Account UPN

       // Get information from Primary Account Link
       if ( savedScore != null && ( savedScore == 3 || savedScore == 1 ) ) {
         updatedAttrValue = savedLink.getAttribute(azureAttribute);
         plog.trace( "ARL-DAUE-019::updatedAttrValue ="+updatedAttrValue); 
       } else {
           plog.trace( "ARL-DAUE-020::currentAttrValue ="+currentAttrValue); 
           //If currentAttrValue is null use azure attribute value else retain the existing
           if(Util.isNullOrEmpty(currentAttrValue) && savedLink != null){
             updatedAttrValue = savedLink.getAttribute(azureAttribute);
           } else {
             updatedAttrValue = currentAttrValue;
           }
           plog.trace( "ARL-DAUE-021::updatedAttrValue ="+updatedAttrValue); 
       }
     } else {
       // There is a problem as we should have at least one Link or we would not be here
       updatedAttrValue = currentAttrValue;
       plog.trace( "ARL-DAUE-022::updatedAttrValue ="+updatedAttrValue); 
       plog.error( "ARL-DAUE-023 Identity: " + identityName + " has no Azure links." );
     }
   } else {
     // Non employee/contractor users email do not come from Azure
     if (Util.nullSafeCaseInsensitiveEq(spAttribute,"email")){
       updatedAttrValue = currentAttrValue;
       plog.trace( "ARL-DAUE-024::updatedAttrValue ="+updatedAttrValue); 
     }
     // UPN from Azure for Supplier and it is safe to retrive it from Azure for Non employee and contractor
     if (Util.nullSafeCaseInsensitiveEq(spAttribute,"userPrincipalName")){
       updatedAttrValue=identity.getAttribute(spAttribute);
       plog.trace( "ARL-DAUE-025::updatedAttrValue ="+updatedAttrValue); 
       if (azureLinks != null && !azureLinks.isEmpty()){
         if ( !Util.nullSafeCaseInsensitiveEq( identityType, "supplier") || azureLinks.size() == 1){
           Link azureLink=azureLinks.get(0);
           plog.trace( "ARL-DAUE-026::azureLink ="+azureLink); 
           updatedAttrValue=getUPNOrMail( context, azureLink );
           plog.trace( "ARL-DAUE-027::updatedAttrValue ="+updatedAttrValue); 
         }
         else {
           plog.error( "ARL-DAUE-028 Violation: Supplier User " + identityName + " has more than one Auzre Acounts.");
         }
       }
     }
   }

   plog.trace( "ARL-DAUE-029::updatedAttrValue ="+updatedAttrValue); 
   plog.trace( "ARL-DAUE-030::Exiting Attribute Rule Library - determineAzureUpnEmail "); 
   return updatedAttrValue;
 }

 public String upnEmailIdentityAttribute(Identity identity, Link link, String spAttribute , String azureAttribute) {
   plog.trace( "ARL-UEA-001::Entering Attribute Rule Library - upnEmailIdentityAttribute ");
   String response;
   plog.trace( "ARL-UEA-002::spAttribute = "+spAttribute +" azureAttribute= " +azureAttribute);
   Application linkApp = link.getApplication();
   plog.trace( "ARL-UEA-003::linkApp = "+linkApp);
   String newValue = determineAzureUpnEmail( context, identity, linkApp, spAttribute ,azureAttribute);
   plog.trace( "ARL-UEA-004::newValue = "+newValue);
   if ( Util.isNotNullOrEmpty(newValue) ) {
     response = newValue;
     plog.trace( "ARL-UEA-005::response = "+response);
   } else {
     response = identity.getAttribute(spAttribute);
     plog.trace( "ARL-UEA-006::response = "+response);
   }
   plog.trace( "ARL-UEA-007::response = "+response);
   plog.trace( "ARL-UEA-008::Exiting Attribute Rule Library - upnEmailIdentityAttribute ");

   return response;
 }


 public static Map getIdentityNameData( SailPointContext context, Identity identity ) {
   Map identityNameData = new HashMap();
   String firstname;
   String lastname;
   String middlename;
   String preferredFirstname;
   String preferredLastname;
   String preferredMiddlename;
   String companyCode;
   String pronoun;
   boolean isPreferredName = false;

   if (identity != null) {
     preferredFirstname = identity.getAttribute( "preferred_first_name" );
     firstName = identity.getAttribute( "firstname" );
     preferredLastname = identity.getAttribute( "preferred_last_name" );
     lastName = identity.getAttribute( "lastname" );
     preferredMiddlename = identity.getAttribute( "preferred_middle_name" );
     middleName = identity.getAttribute( "middleName" );

     pronoun = identity.getAttribute( "pronoun" );
     identityNameData.put( "pronoun", pronoun );

     companyCode = identity.getAttribute( "companyCode" );
     identityNameData.put( "companyCode", companyCode );

     if ( Util.isNotNullOrEmpty( preferredFirstname ) || Util.isNotNullOrEmpty( preferredLastname ) || Util.isNotNullOrEmpty( preferredMiddlename ) ) {
       isPreferredNameExist = true;
       identityNameData.put( "preferredName", isPreferredName );
       identityNameData.put( "firstname", preferredFirstname );
       identityNameData.put( "lastname", preferredLastname );
       identityNameData.put( "middlename", preferredMiddlename );
     } else {
       identityNameData.put( "preferredName", isPreferredName );
       identityNameData.put( "firstname", firstname );
       identityNameData.put( "lastname", lastname );
       identityNameData.put( "middlename", middlename );
     }
   }
   return identityNameData;
 }

 // this method will look into provided Azure account to check if a email license has been assigned to the user
 public boolean checkAzureForEmailLicense(Link azureLink) {

   plog.trace( "ARL-CAL-001::Entering Attribute Rule Library - checkAzureForEmailLicense ");
   boolean azureHasEmail = false;

   // build list of possible plans with Exchange
   List exchangePlans = new ArrayList();
   exchangePlans.add( "EOP_ENTERPRISE" );
   exchangePlans.add( "EOP_ENTERPRISE_PREMIUM" );
   exchangePlans.add( "EXCHANGE_ANALYTICS" );
   exchangePlans.add( "EXCHANGE_B_STANDARD" );
   exchangePlans.add( "EXCHANGE_L_STANDARD" );
   exchangePlans.add( "EXCHANGE_S_ARCHIVE" );
   exchangePlans.add( "EXCHANGE_S_ARCHIVE_ADDON" );
   exchangePlans.add( "EXCHANGE_S_DESKLESS" );
   exchangePlans.add( "EXCHANGE_S_ENTERPRISE" );
   exchangePlans.add( "EXCHANGE_S_ESSENTIALS" );
   exchangePlans.add( "EXCHANGE_S_FOUNDATION" );
   exchangePlans.add( "EXCHANGE_S_STANDARD" );
   exchangePlans.add( "EXCHANGE_S_STANDARD_MIDMARKET" );
   exchangePlans.add( "EXCHANGEONLINE_MULTIGEO" );

   List azureALs = azureLink.getAttribute( "assignedLicenses" );
   List assignedPlans = azureLink.getAttribute( "assignedPlans" );
   plog.trace( "ARL-CAL-002::azureALs = "+azureALs);
   plog.trace( "ARL-CAL-003::assignedPlans = "+assignedPlans);
   if ( assignedPlans != null ) {
     for ( String assignedPlan : assignedPlans ) {
       String plan = assignedPlan.split( " : " )[1];
       plog.trace( "ARL-CAL-004::plan = "+plan);
       if ( Util.isNotNullOrEmpty( plan ) && exchangePlans.contains( plan ) ) {
         azureHasEmail = true;
         plog.trace( "ARL-CAL-005::azureHasEmail = "+azureHasEmail);
       }
     }
   }
   if ( azureALs != null && azureALs.contains( "ENTERPRISEPREMIUM" ) ) {
     azureHasEmail = true;
     plog.trace( "ARL-CAL-006::ENTERPRISEPREMIUM azureHasEmail = "+azureHasEmail);
   }
   plog.trace( "ARL-CAL-007::azureHasEmail = "+azureHasEmail);
   plog.trace( "ARL-CAL-008::Exiting Attribute Rule Library - checkAzureForEmailLicense ");
   return azureHasEmail;
 }

 // this method will evaluate if the user needs their email attribute value synced up in Azure AD
 public boolean needsEmailAttributeSyncUp (Identity identity, Link link) {

   plog.trace( "ARL-NES-001 Entering Attribute Rule Library - needsEmailAttributeSyncUp : " + identity.getName() );

   /* if a TFS user has AD NA account and user has email license assigned, Do NOT update email value
   criteria-1 = the update request is for a TFS user
   criteria-2 = user has AD NA account
   criteria-3 = user has email license assigned to their Azure AD account */

   boolean returnVal = false;
   Application adApp = link.getApplication();
   List tfsCompanyCodes = new ArrayList();
   if(adApp.getAttributeValue("tfsCompanyCodes")!=null){
     tfsCompanyCodes.addAll(adApp.getAttributeValue("tfsCompanyCodes"));
   }
   List tcnCompanyCodes = new ArrayList();
   if(adApp.getAttributeValue("tcnCompanyCodes")!=null){
     tcnCompanyCodes.addAll(adApp.getAttributeValue("tcnCompanyCodes"));
   }
   List syncExceptionCompanyCodes = new ArrayList();
   syncExceptionCompanyCodes.addAll(tfsCompanyCodes);
   syncExceptionCompanyCodes.addAll(tcnCompanyCodes);

   //criteria-1: get user's company code value
   String companyCode = getIdentityAttribute(context, identity, "companyCode");

   plog.trace( "ARL-NES-002 companyCode : " + companyCode );
   plog.trace( "ARL-NES-003 syncExceptionCompanyCodes : " + syncExceptionCompanyCodes );

   if (Util.isNotNullOrEmpty(companyCode) && syncExceptionCompanyCodes.contains(companyCode)) {

     /* criteria-2: if company code starts with TFS or TCN, need to check if user also has AD NA acount
     however, the method is only triggered for users with AD NA account with the link value passed as a method arguement, so skip app account check.
     criteria-3: check if email license is also assigned to user */

     boolean azureHasEmail = false;
     Application azureApp = context.getObjectByName(Application.class, "Azure AD");
     List azurelinks = new ArrayList();
     IdentityService idService = new IdentityService(context);
     azurelinks = idService.getLinks(identity, azureApp);
     if (!azurelinks.isEmpty() && azurelinks.size()>0) {
       for (Link azureLink : azurelinks) {
         plog.trace( "ARL-NES-004 azureHasEmail : " + azureHasEmail );
         if (!azureHasEmail) {
           if(tcnCompanyCodes.contains(companyCode)){
             //Check the if the Azure link is authoritative domain example: DC=TMM
             String onPremisesDistinguishedName = azureLink.getAttribute( "onPremisesDistinguishedName" );
             plog.trace( "ARL-NES-005 onPremisesDistinguishedName : " + onPremisesDistinguishedName ); 
             List authoritativeDomains = getAuthoritativeDomains();
             plog.trace( "ARL-NES-006 authoritativeDomains : " + authoritativeDomains );
             if ( Util.isNotNullOrEmpty( onPremisesDistinguishedName ) ) {
               String azureDomainKey = onPremisesDistinguishedName.toUpperCase().split(",DC=")[1];
               plog.trace( "ARL-NES-007 azureDomainKey : " + azureDomainKey );
               if ( authoritativeDomains != null && authoritativeDomains.contains( azureDomainKey ) ) {
                 plog.trace( "ARL-NES-008 identity.getName()::"+identity.getName() +" User company code is TCN and Azure link is related to authoritative domain,hence license check is skipped." );
               }else {
                 azureHasEmail = checkAzureForEmailLicense(azureLink);
               }
             }
           }else {
             azureHasEmail = checkAzureForEmailLicense(azureLink);
           }
         }
       }
     }
     plog.trace( "ARL-NES-009 azureHasEmail : " + azureHasEmail );        
     if (azureHasEmail) {
       /* criteria-1, criteria-2, criteria-3 are all met
       no need to update email value, so returning original value from account link */
       returnVal = false;
     }
     else {
       //filter criteria not met, proceed with target mapping as initiated
       returnVal = true;
     }
   }
   else {
     returnVal = true;
   }
   plog.trace( "ARL-NES-010 returnVal : " + returnVal );
   plog.trace( "ARL-NES-011 Exiting Attribute Rule Library - needsEmailAttributeSyncUp : " + identity.getName() );
   return returnVal;
 }

 public Date expirationdate(String selectedIdentityId, String type, String expirationDate){
   Logger alog=Logger.getLogger("rule.ExtendedExpirationDate");

   Calendar calendar = Calendar.getInstance();
   calendar.add(Calendar.YEAR, 1);
   Date nextYear = calendar.getTime();
   if(selectedIdentityId != null){
     Identity identity=context.getObjectById(Identity.class,selectedIdentityId);
     if(identity != null)
     {
       if(alog.isTraceEnabled()) {
         alog.trace("ARL-ED-001 Starting ExtendedExpirationDateFieldForm for " +identity.getName());
       }

       if(form.getField("type") != null && form.getField("expirationDate") != null){
         String type = form.getField("type").getValue();
         String expiryDate = form.getField("expirationDate").getValue();
         if(type!=null && "contractor".equalsIgnoreCase(type)){
           if(expiryDate != null && !"never".equalsIgnoreCase(expiryDate)){
             nextYear = Util.getEndOfDay(nextYear);
           }
           else{
             nextYear = Util.getEndOfDay(nextYear);
           }
         }
       }
       if(alog.isTraceEnabled()) {
         alog.trace("ARL-ED-002 Ending ExtendedExpirationDateFieldForm for " +identity.getName()+" date:"+nextYear);
       }
     }
     else
     {
       alog.error("ARL-ED-003 Expiration extension for Identity ID" +selectedIdentityId+" failed as Identity not found in system");
     }
   }
   return nextYear;
 }


