 /*****
   Method to format date of either a String or Date Object when the type is unknown
   Returns a formatted date as a string
   For formatting options please review:
     https://docs.oracle.com/javase/7/docs/api/java/text/SimpleDateFormat.html
 *****/
 public static String formatDateOrStringObject( Object dateObject, String formatString ) {
   String formattedDateString = "";

   if ( dateObject != null ) {
     if ( Util.isNotNullOrEmpty( formatString ) ) {
       try {

         Date workingDate;
         if ( dateObject instanceof Date ) {
           // The dateObject is of type Date.  Set the value for working
           workingDate = (Date) dateObject;
         } else if ( dateObject instanceof String ) {
           // The dateObject is of type String.  Convert to Date for working
           workingDate = Util.stringToDate( dateObject );
         }

         // Set the date format
         SimpleDateFormat formatter = new SimpleDateFormat( formatString );
         formattedDateString = formatter.format( workingDate );

       } catch ( Exception ex ) {
         plog.error( "ARL-FDSO-001 Exception Formatting Date: " + ex.getMessage() );
       }
     } else {
       plog.error( "ARL-FDSO-002 Cannot format null Date/String Object with missing formatString" );
     }
   } else {
     plog.error( "ARL-FDSO-003 Cannot format null Date/String Object as date" );
   }
   return formattedDateString;
 }

 /*
   Truncates a value at a specified length

   @value Input string to be truncated
   @length Length of the string to be truncated
 */
 public static String truncateValue( String value, int length ) {
   if ( value != null ) {
     // Truncate the length to 40 chars  
     if ( value.length() > length ) {
       value = value.substring( 0, length - 1 );              
     }             

     // Clean up and extra whitespace
     value = value.trim();
   }  
   return value;
 }

 /*
   Delete the attribute from link Active Directory - NA if attribute value is same but different case

   @attributeValue Input string value
   @link link object
   attributeName Name of attribute
 */
 public void deleteLinkAttrForCaseSensitive(SailPointContext context, String attributeValue, Link link, String attributeName){
   String linkAttributeValue = link.getAttribute(attributeName);
   if (attributeValue != null && linkAttributeValue!=null && attributeValue.equalsIgnoreCase(linkAttributeValue) && !attributeValue.equals(linkAttributeValue)) {
     link.setAttribute(attributeName, "");
     context.saveObject(link);
   }
 }

