 /*******
   Get Direct Reportees
 *******/
 public static Object getDirectReportees( SailPointContext context, Identity identity, String type ) {
   if ( plog.isTraceEnabled() ) {
     plog.trace( "ARL-GDR-001: Entering Attribute Rule Library - getDirectReportees: "+identity.getName()+" "+ type);
   }
   ArrayList reportees = new ArrayList();
   QueryOptions qo=new QueryOptions();
   qo.addFilter(Filter.eq("manager.name", identity.getName()));
   qo.addFilter(Filter.eq("type", type));
   qo.addFilter(Filter.eq("inactive",false));
   Iterator it = context.search( Identity.class, qo, "name" );
   if ( it != null ) {
       while ( it.hasNext() ) {
         Object [] thisRecord = it.next();
         String identityName = thisRecord[0];
         reportees.add(identityName);
       }
   }
   Util.flushIterator(it);
   plog.trace( "ARL-GDR-002: "+type+" reportees of "+identity.getName()+" "+ reportees);
   return reportees;
 }

 public static ProvisioningPlan buildIdentityAttributeUpdatePlan(String identityName)
 {
   plog.trace( "ARL-BIAUP-001 Entering Emergency Account Termination IdentityAttribute Update");
   if (identityName != null) {
     Identity identity = context.getObjectByName(Identity.class,identityName);
     ProvisioningPlan plan = new ProvisioningPlan();
     plan.setIdentity(identity);
     Date currentDate = new Date();
     String stringDate=new SimpleDateFormat("MM/dd/yyyy").format(currentDate);
     AccountRequest acctReq = new AccountRequest();
     acctReq.setApplication("IIQ");
     acctReq.setNativeIdentity(identity.getName());
     acctReq.setOp(ProvisioningPlan.ObjectOperation.Modify);
     acctReq.add(new AttributeRequest("emergencyLeaverDate",ProvisioningPlan.Operation.Set,stringDate));
     acctReq.add(new AttributeRequest("inactive",ProvisioningPlan.Operation.Set,true));
     plan.add(acctReq);
     return plan;
   }
 }
