 /*******
   This method is used to get the user's numerical subtype
   * @param context SailPointContext
   * @param typeValue UserType of the user
   * @param identity identity object of the user
 *******/
 public static int getWorkerType(SailPointContext context, Identity identity, String typeValue)
 {
   plog.trace("ARL-GWT-001 Entering Attribute Rule Library - getWorkerType:" + identity.getName());
   plog.trace("ARL-GWT-002 typeValue:" + typeValue);
   int wType = 0;
   if (typeValue !=null && typeValue.equalsIgnoreCase("contractor")) {
     wType = 10;
   }
   else if (typeValue !=null && typeValue.equalsIgnoreCase("employee")) {
     wType = 1;
     String empClass= getIdentityAttribute( context, identity, "employee_class" );
     if ( empClass !=null && empClass.equalsIgnoreCase("I") ) {
       wType = 3;
     }
   }
   plog.trace("ARL-GWT-005 returned wType:" + wType);
   return wType;
 }

