 public static String getGUIDformattedEmailForInactiveUsers(SailPointContext context, Identity identity)
 {  
   plog.trace("ARL-GSE-001 Entering Attribute Rule Library - getStatusBasedEmail:" + identity.getName());
   boolean inactive = identity.isInactive();
   String email= getIdentityAttribute( context, identity, "email" );
   String guid = getIdentityAttribute(context, identity, "guid");
   plog.trace("ARL-GSE-002 guid for the user "+guid);
   if(inactive && Util.isNotNullOrEmpty(email)){
     email = guid +email.substring(email.indexOf("@"),email.length());
   }else if(inactive && Util.isNullOrEmpty(email)){
     email = guid + "@toyota.com";
   }
   plog.trace("ARL-GSE-003 email For the user "+email);
   return email;
 }

   /**
   * Generates a valid email address for an identity, defaulting to a placeholder if none provided.
   * 
   * This method ensures that every identity has an associated email address. If no valid email
   * is provided, it constructs a default email using the identity's Workday ID.
   * 
   * @param context The SailPoint context for accessing system resources
   * @param identity The Identity object for which to get or generate an email address
   * @param email The provided email address (can be null or empty)
   * @return A valid email address - either the provided email or a generated placeholder
   *         in the format "{workday_id}_invalid@toyota.com"
 */
 public static String getEmailAddress(SailPointContext context, Identity identity, String email)
 { 
   plog.trace("ARL-GEA-001 Entering Attribute Rule Library - getEmailAddress:"+identity.getName());
   String workdayID = getIdentityAttribute(context, identity, "workday_id");
   plog.trace("ARL-GEA-002 workdayID:"+workdayID);
   String emailToSend = email;
   if (Util.isNullOrEmpty( email )) {
     emailToSend = workdayID+"_invalid@toyota.com";
   }
   return emailToSend;
 }

 /**
   * Determines the employment status based on the input status code.
   * 
   * @param status The employee status code.
   * @return "Active" if the status code is A, L, or P; "Terminated" otherwise
 */
 public static String getEmploymentStatus(String status)
 { 
   plog.trace("ARL-GES-001 Entering Attribute Rule Library - getEmploymentStatus");
   if (status != null) {
     if (status.matches("A")) {
       return  "1";
     }
     else if (status.matches("D")) {
       return  "6";
     }
     else if (status.matches("I")) {
       return  "2";
     }
     else if (status.matches("L")) {
       return  "9";
     }
     else if (status.matches("R")) {
       return  "5";
     }
     else if (status.matches("T")) {
       return  "102";
     }
   } else {
     return  "100";
   }
 }

 /**
   * Generates a formatted string containing hire and rehire dates for an identity.
   * 
   * This method retrieves the original hire date from the Workday TMNA application
   * and combines it with the rehire date (if provided) to create a formatted string.
   * 
   * @param context The SailPoint context used for accessing application data
   * @param identity The Identity object for which to retrieve hire date information
   * @param rehireDate The rehire date string, can be null or empty if the employee was not rehired
   * @return A formatted string containing:
   *         - "Hire Date: {originalHireDate} ReHire Date: {rehireDate}" if rehireDate is provided
   *         - "Hire Date: {originalHireDate}" if rehireDate is null or empty
 */
 public static String getHireAndRehireDate(SailPointContext context, Identity identity,String rehireDate)
 { 
   plog.trace("ARL-GHRD-001 Entering Attribute Rule Library - getHireRehireDate:"+identity.getName());
   plog.trace("ARL-GHRD-002 rehireDate:"+rehireDate);
   String workdayOriginalHireDate =  getApplicationAttribute( context, identity, "Workday TMNA" , "ORIGINAL_HIRE_DATE" );
   plog.trace("ARL-GHRD-003 workdayOriginalHireDate:"+workdayOriginalHireDate);
   if ( Util.isNotNullOrEmpty(rehireDate ) ) {
     return "Hire Date:" + workdayOriginalHireDate + " ReHire Date:" + rehireDate;
   } else {
     return "Hire Date:" + workdayOriginalHireDate;
   }
 }

 /**
   * Converts a termination date string to YYYY-MM-DD format.
   * 
   * @param terminationDate the termination date string to be converted
   * @return the termination date formatted as YYYY-MM-DD
 */
 public static String getTerminationDateYYYYMMDD(String terminationDate)
 { 
   plog.trace("ARL-GTD-001 Entering Attribute Rule Library - getTerminationDateYYYY-MM-DD");
   plog.trace("ARL-GTD-002 terminationDate:"+terminationDate);
   if ( terminationDate!= null  && terminationDate.contains("/") )
   {
     String[] termDateSplit = terminationDate.split("/");
     if ( termDateSplit.length == 3 )
     { 
       return termDateSplit[2] + "-" + termDateSplit[0] + "-" + termDateSplit[1];
     }
   } else {
     return terminationDate;
   }
 }

 /**
   * Determines the appropriate tag value based on the provided status. 
   * This method evaluates the status parameter and returns a corresponding tag string.
   * @param status A single character status code.
 */
 public static String getStatusTag(String status)
 { 
   plog.trace("ARL-GST-001 Entering Attribute Rule Library - getStatusTag");
   plog.trace("ARL-GST-002 status:"+status);
   String tagsValue = "Do Not Email; Terminated";
   if (status .matches("A|L|P"))
   {
     tagsValue = "- Do Not Email; - Terminated";
   }
   plog.trace("ARL-GST-003 tagsValue:"+tagsValue);
   return tagsValue;
 }
